(window.courseContentFiles = window.courseContentFiles || {})["000003/0009"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n      line-height: 1.3;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    p + p {\n      margin-top: 0.55em;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    h1 + table, h2 + table, h3 + table, h4 + table {\n      margin-top: -0.2em;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      p + p { margin-top: 0.55em; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\"><span style=\"color: rgb(255, 192, 0)\">Анатомия и физиология</span></h1><p>При нормални условия бъбреците тежат около <strong>150 g</strong>, с размери приблизително <strong>13 × 6 cm</strong>, и получават около <strong>25% от сърдечния дебит</strong>.</p><h2>Ангиоархитектоника</h2><p>Бъбречната артерия се разклонява на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270181613-image.png &quot;width=100%&quot;)\" id=\"note-1778270183014-0\">интерлобарни артерии</span></strong>, които условно разделят бъбрека на около <strong>12 лоба</strong>. Всяка интерлобарна артерия се разделя на <strong>дъговидни артерии</strong>, разположени на границата между кората и пирамидите. От тях започват <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270217203-image.png &quot;width=100%&quot;)\" id=\"note-1778270218990-1\">интерлобуларните артерии</span></strong>, които се насочват към кората.</p><p>При масивна кръвозагуба гладкомускулните клетки в началната част на тези съдове могат да се контрахират и да обезкръвят външната корова тъкан — т.нар. <strong>шънт на Trueta</strong>.</p><p>От интерлобуларните артерии изхождат <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270250495-image.png &quot;width=100%&quot;)\" id=\"note-1778270251529-2\">аферентните артериоли</span></strong>, които дават начало на гломерулните капилярни сплитове. Кръвта се събира в <strong>еферентна артериола</strong>, която след гломерула се разпада на <strong>rete mirabilis</strong> — „чудна капилярна мрежа“, оросяваща каналчето на същия нефрон.</p><p>Ако кръвотокът в еферентната артериола спре поради патологично запушване на аферентната артериола или гломерулните капиляри, загива целият нефрон. Венозните съдове следват хода на артериалните.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Юкстагломеруларен апарат</h2><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270365541-image.png &quot;width=100%&quot;)\" id=\"note-1778270366857-3\">Юкстагломеруларният апарат (ЮГА)</span></strong> се намира в съдовия полюс на бъбречното телце и включва три основни компонента:</p><ul><li><strong>гранулирани миоепителни клетки</strong> в стената на аферентната артериола, които секретират ренин и еритропоетин;</li><li><strong>macula densa</strong> — участък от дисталното извито каналче, който регулира секрецията на ренин според йонното съдържание на урината;</li><li><strong>екстрагломеруларен мезангиум</strong> — маса от звездовидни клетки между аферентната и еферентната артериола.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270390417-image.png &quot;width=100%&quot;)\" id=\"note-1778270391426-4\">Нефрон</span></h2><p><strong>Нефронът</strong> е основната структурно-функционална единица на бъбрека. Всеки бъбрек съдържа над <strong>1 милион нефрони</strong>.</p><p>Нефронът започва от <strong>бъбречното телце</strong> и включва <strong>проксимални каналчета</strong>, <strong>Хенлева бримка</strong> и <strong>дистални извити каналчета</strong>.</p><h2><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fupload.wikimedia.org%2Fwikipedia%2Fcommons%2Fthumb%2F6%2F69%2FRenal_corpuscle-en.svg%2F600px-Renal_corpuscle-en.svg.png&amp;f=1&amp;nofb=1&amp;ipt=616671eec4eb7bfa1f851a12eaa4764415b0b046275384e73d861f6c079ba769 &quot;width=100%&quot;)\" id=\"note-1778270612271-5\">Бъбречно телце</span></h2><p>Бъбречното телце е изградено от <strong>гломерул</strong> — сплетение от специализирани капиляри — и <strong>Бауманова капсула</strong>. Между двата листа на капсулата се намира <strong>уринарното пространство</strong>, което се дренира в проксималното каналче.</p><p>Аферентната артериола се разделя на 3–5 първични клона, които образуват гломерулни лобове. Капилярите се разполагат около <strong>мезангиални оси</strong>, обгърнати от подоцитите на висцералния лист на Баумановата капсула.</p><p>Нормално в екваториален срез на гломерула има не повече от <strong>150 ядра</strong>, а в една мезангиална зона — не повече от <strong>2 клетки</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ултраструктура на гломерула</h2><p>Ендотелните клетки на гломерулните капиляри имат множество отвори - <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-08/text-editor-images/2026/05/1778270641723-image.png &quot;width=100%&quot;)\" id=\"note-1778270739987-7\">fenestrae</span></strong>, поради което ендотелната бариера се нарича <strong>membrana fenestrata</strong>. Филтрационната ѝ способност зависи не толкова от големината на порите, а главно от <strong>отрицателния електростатичен заряд</strong>.</p><p><strong>Гломерулната базална мембрана</strong> е дебела около <strong>350 nm</strong> и има трислоен строеж: </p><ul><li>централна плътна <strong>lamina densa</strong></li><li>вътрешна <strong>lamina rara interna</strong> към ендотела</li><li>външна <strong>lamina rara externa</strong>, в която се вграждат крачетата на подоцитите</li></ul><p><strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Ftse4.mm.bing.net%2Fth%2Fid%2FOIP.BO8tJ1cYRHX5EteiH1TeHwAAAA%3Fr%3D0%26pid%3DApi&amp;f=1&amp;ipt=18fbcedc593bda55f26d149ee30c6d2ed91a799bb1e9aa0796c276496b181349&amp;ipo=images &quot;width=100%&quot;)\" id=\"note-1778270854927-8\">Подоцитите</span></strong> са клетките на висцералния лист на Баумановата капсула. Те имат множество израстъци — <strong>педикули</strong>, които се преплитат помежду си и образуват процепи. Тези процепи са по-малки от фенестрите на ендотела и участват във филтрационната бариера.</p><p>Повърхността на клетките е покрита с <strong>гликокаликс</strong>, а заедно с полианионните протеогликани на базалната мембрана създава отрицателен заряд на гломерулния филтър. Затова филтърът пропуска вода, йони и малки молекули, но задържа макромолекули. <strong>Албуминът нормално не преминава във филтрата</strong>.</p><h2>Мезангиум</h2><p><strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fo.quizlet.com%2FDLVxd8yEXb3Xs.YjFfufCA.jpg&amp;f=1&amp;nofb=1&amp;ipt=879d01a40110839f01424d8f425439d739b86033cbcd781ecc8b1380dc8bc8dd &quot;width=100%&quot;)\" id=\"note-1778270930594-9\">Мезангиумът</span></strong> е изграден от спонгиозна мрежа от базалномембраноподобен материал и интеркапилярни мезангиални клетки. Той функционира като синцитиум.</p><p>Мезангиалните клетки имат <strong>макрофагеална природа</strong>. Те могат да контактуват с лимфоцити и да фагоцитират едри молекули и <strong>имунни комплекси</strong>, задържани в базалната мембрана.</p><p>Париеталният лист на Баумановата капсула е изграден от приплеснати епителни клетки, бедни на органели.</p><h2><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Finfinitylearn.com%2Fsurge%2Fwp-content%2Fuploads%2F2024%2F07%2FStructure-of-Renal-Tubule.jpg&amp;f=1&amp;nofb=1&amp;ipt=10df2195d9cce81f24215d7e1256147ab2b3a989c039279f1d729ace350ee711 &quot;width=100%&quot;)\" id=\"note-1778271027494-10\">Тубули</span></h2><p>Строежът на тубуларния епител отговаря на функцията на съответния сегмент на нефрона.</p><p>Клетките на <strong>проксималните извити каналчета</strong> имат обилни дълги микровили, които увеличават площта за реабсорбция на <strong>натрий, глюкоза, калий, фосфати и белтъци</strong>. В базалната част има много митохондрии, осигуряващи енергия за активния транспорт.</p><p>В бъбречната кора се намират <strong>проксималните и дисталните извити каналчета</strong>, а в медулата — <strong>Хенлевата бримка</strong>. Епителът на възходящото рамо на Хенлевата бримка секретира <strong>белтък на Tamm-Horsfall</strong>.</p><p>В кората нефроните се вливат в <strong>събирателни каналчета</strong>, които преминават през медулата и се отварят на повърхността на бъбречните папили.</p><h2><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fd3i71xaburhd42.cloudfront.net%2F0da22037ef7c0aa84964d0ef5092bfb7e4173ab4%2F2-Figure1-1.png&amp;f=1&amp;nofb=1&amp;ipt=3845b4a64cb291ce6ce924977f37af2071dfa8e2c58a06429286f42a09ab7b7c &quot;width=100%&quot;)\" id=\"note-1778271068549-11\">Интерстициум</span></h2><p>Интерстициумът е съставен от <strong>фибробластоподобни клетки</strong> и основно вещество. Реномедуларните интерстициални клетки синтезират <strong>антихипертензивни простагландини</strong>.</p><h2>Пикочоотводящи пътища</h2><p>Пикочоотводящите пътища са покрити с <strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fi.ytimg.com%2Fvi%2F_YmP0_u0Tak%2Fmaxresdefault.jpg&amp;f=1&amp;nofb=1&amp;ipt=37ae6b77bc9e6af0e2033918bc1ed95353a198e0bb7240dc1d0aa3bd64f949f3 &quot;width=100%&quot;)\" id=\"note-1778271201060-12\">преходен епител / уротел</span></strong>, разположен върху нежна базална мембрана. Повърхностно се намират големи, понякога двуядрени <strong>„чадърести“ клетки</strong> с обилна еозинофилна цитоплазма.</p><p>Преходният епител е с различна дебелина: в легенчето е от <strong>2–3 клетъчни слоя</strong>, в уретера — около <strong>5 слоя</strong>, а в пикочния мехур варира според разтягането — около <strong>2 слоя при пълен мехур</strong> и до <strong>7 слоя при празен</strong>.</p><p><strong>Уретерите</strong> са дълги около <strong>30 cm</strong> и имат три физиологични стеснения, важни за запушване от конкременти: уретеро-пелвичната връзка, мястото на кръстосване с илиачните съдове и входа в пикочния мехур.</p><p>Уретерите навлизат косо в мехурната стена и завършват в тригонума. При изпълване на мехура мускулатурата притиска вътрестенната част на уретера и действа като <strong>сфинктерна клапа</strong>. В дисталната част на уретрата преходният епител преминава в плосък.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Функции на бъбрека</h2><ul><li><strong>Филтрация </strong>на кръвната плазма в гломерулите – първична урина;</li><li><strong>Резорбция </strong>на вода, глюкоза и соли в бримката на хенле при което урината се концентрира;</li><li><strong>Секреция </strong>на ненужни съединения към каналчетата с цел да бъдат изхвърлени с урината – амоняк, урея, креатинин и др.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Основни клинични синдроми при бъбречните заболявания</h2><h3>Нефротичен синдром</h3><p><strong>Нефротичният синдром</strong> се характеризира с масивна протеинурия — над <strong>3.5 g/24 h</strong>, диспротеинемия, хипопротеинемия, хиперлипидемия с хиперхолестеринемия и <strong>отоци</strong>.</p><p>Причината са първични морфологични изменения в <strong>гломерулите</strong>.</p><h3>Нефритен синдром</h3><p>При <strong>нефритния синдром</strong> се наблюдават микро- или макрохематурия, лека до умерена протеинурия, намалена гломерулна филтрация и <strong>олигурия</strong>. Това води до <strong>отоци и хипертония</strong>.</p><p>В хода на основните типове гломерулонефрити може да се развие <strong>дифузен полулунен / бързопрогресиращ гломерулонефрит</strong>, който представлява тежка форма на нефритен синдром и води до <strong>остра бъбречна недостатъчност</strong>.</p><h3>Остра бъбречна недостатъчност</h3><p><strong>Острата бъбречна недостатъчност (ОБН)</strong> се характеризира с <strong>олигурия</strong> — под <strong>400 ml урина/24 h</strong>, и бързо повишаване на уреята и креатинина в кръвта — <strong>азотемия</strong>.</p><p>Обикновено няма значима протеинурия.</p><h3>Хронична бъбречна недостатъчност</h3><p><strong>Хроничната бъбречна недостатъчност (ХБН)</strong> е краен стадий на повечето бъбречни заболявания. Дължи се на тежки изменения на бъбречния паренхим, които водят до намалена гломерулна филтрация и <strong>азотемия</strong>.</p><p><strong>Уремия</strong> означава ХБН с тежка клинична симптоматика, причинена от напреднали морфологични изменения в сърдечно-съдовата, храносмилателната, хемопоетичната система и кожата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Промени в гломерулите и биопсично изследване</h2><p>Основен метод в съвременната нефропатология е <strong>перкутанната пункционна бъбречна биопсия</strong>. Тя позволява морфологична оценка на гломерулите, уточняване на патогенезата, избор на лечение, проследяване на терапевтичния ефект и определяне на прогнозата. Обикновено изследването на около десетина гломерула е достатъчно за точна диагностика на дифузните бъбречни заболявания.</p><p>Клиничната диагноза съвпада с морфологичната само в около <strong>50%</strong> от случаите, поради което биопсичното изследване има голямо значение.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Основни морфологични промени в гломерулите</h2><h3>1. Хиперцелуларност</h3><p><strong>Хиперцелуларност</strong> означава повишен брой клетки в гломерула. Тя може да се дължи на:</p><ul><li>пролиферация на <strong>мезангиални клетки</strong>;</li><li>пролиферация на <strong>ендотелни клетки</strong>;</li><li>инфилтрация от <strong>неутрофили</strong>, <strong>моноцити</strong> и по-рядко лимфоцити.</li></ul><p>При острия гломерулонефрит хиперцелуларността често е предимно за сметка на <strong>неутрофили</strong>.</p><p>При някои имунни и възпалителни заболявания се образуват <strong>полулуния</strong>. Те се състоят от пролифериращи париетални епителни клетки и моноцити, с примес от левкоцити. Основната причина за тяхното формиране е увреждане на гломерулната базална мембрана. В резултат <strong>фибриноген</strong> преминава в Баумановото пространство и се превръща във <strong>фибрин</strong>, който стимулира клетъчната пролиферация.</p><p>Полулунията притискат гломерулната капилярна мрежа и я изключват функционално. Най-широката част на полулунието обикновено е противоположна на съдовия полюс.</p><p>Могат да се наблюдават и <strong>синехии</strong> между капилярните бримки и париеталния лист на Баумановата капсула.</p><h3>2. Задебеляване на капилярната стена и базалната мембрана</h3><p>Задебеляването на капилярната стена се оценява добре със <strong>PAS-оцветяване</strong> при светлинна микроскопия. При електронна микроскопия често се установяват отлагания от <strong>аморфен електронноплътен материал</strong>, най-често имунни комплекси.</p><p>Депозитите могат да бъдат разположени:</p><ul><li><strong>субендотелно</strong> — от ендотелната страна на базалната мембрана;</li><li><strong>субепително</strong> — от епителната страна;</li><li><strong>интрамембранозно</strong> — в самата базална мембрана;</li><li><strong>мезангиално</strong> — в мезангиума.</li></ul><p>Освен имунни комплекси могат да се отлагат и други вещества, например:</p><ul><li><strong>фибрин</strong>;</li><li><strong>амилоид</strong>;</li><li><strong>криоглобулини</strong>;</li><li>абнормни фибриларни протеини.</li></ul><p><strong>Задебеляване на собствената базална мембрана</strong> се наблюдава например при <strong>диабетна гломерулосклероза на Kimmelstiel-Wilson</strong>.</p><p>При <strong>мембранозна гломерулопатия</strong> има задебеляване на капилярната стена и базалната мембрана, като капилярните лумени остават отворени и няма значимо увеличаване на клетъчността.</p><h3>3. Хиалинизация и склероза</h3><p>При светлинна микроскопия <strong>хиалинизацията</strong> изглежда като хомогенна <strong>еозинофилна материя</strong>. При електронна микроскопия тя представлява екстрацелуларна аморфна субстанция, произхождаща основно от плазмени компоненти.</p><p>Постепенно настъпва:</p><ol><li>пропиване на капилярната стена;</li><li>стесняване на капилярния лумен;</li><li>фиброза;</li><li><strong>склероза</strong>.</li></ol><p>Хиалинизацията и склерозата са резултат от увреждане на ендотела или капилярната стена. Те могат да се съчетават с:</p><ul><li><strong>интрагломерулна тромбоза</strong>;</li><li>отлагане на липиди;</li><li>натрупване на други метаболитни продукти.</li></ul><p>Хиалинизираните гломерули са с намален размер и загубена функция. Останалите запазени гломерули могат компенсаторно да се уголемят, за да поемат допълнителната функция. При изразена склероза бъбрекът макроскопски може да бъде <strong>сбръчкан</strong>.</p><h2>Комплексно биопсично изследване</h2><p>Бъбречната биопсия се изследва чрез няколко допълващи се метода: <strong>светлинна микроскопия</strong>, <strong>имунофлуоресценция</strong>, <strong>електронна микроскопия</strong> и <strong>хистохимично изследване</strong>.</p><h3>1. Светлинна микроскопия</h3><p>Материалът се фиксира във формалин и се оцветява с:</p><ul><li><strong>H-E</strong>;</li><li><strong>PAS</strong>;</li><li>сребърна импрегнация по <strong>Jones/Wilder</strong>;</li><li>трихром по <strong>Masson</strong>.</li></ul><p>Тези методи позволяват оценка на:</p><ul><li>клетъчността на гломерулите;</li><li>базалните мембрани;</li><li>степента на фиброза;</li><li>хиалинизацията и склерозата;</li><li>понякога и визуализация на имунни комплекси.</li></ul><h3>2. Имунофлуоресцентно изследване</h3><p>Използват се криостатни срези от свежа нефиксирана тъкан. Методът локализира:</p><ul><li><strong>имуноглобулини</strong> — IgG, IgM, IgA;</li><li>компоненти на комплемента — C3, C4, C1q;</li><li><strong>фибрин</strong>;</li><li>антигени;</li><li>клетъчни маркери.</li></ul><p>При <strong>антибазалномембранен гломерулонефрит</strong> се наблюдава <strong>линеарна флуоресценция</strong> по гломерулните базални мембрани.</p><p>При <strong>имунокомплексни гломерулонефрити</strong> флуоресценцията е <strong>зърниста</strong>. Тя може да бъде разположена:</p><ul><li>по базалната мембрана;</li><li>в мезангиума;</li><li>едновременно по базалната мембрана и в мезангиума.</li></ul><h3>3. Електронна микроскопия</h3><p>При електронна микроскопия имунните комплекси се виждат като <strong>електронноплътни депозити</strong>.</p><p>Те могат да бъдат разположени:</p><ul><li>субендотелно;</li><li>интрамембранозно;</li><li>субепително;</li><li>мезангиално.</li></ul><p>Електронната микроскопия е особено полезна за прецизно определяне на локализацията на депозитите и за оценка на гломерулната базална мембрана.</p><h3>4. Хистохимично изследване</h3><p>Хистохимичните методи се използват за доказване на специфични вещества в тъканта, например:</p><ul><li><strong>фибрин</strong>;</li><li><strong>амилоид</strong>;</li><li><strong>липиди</strong>;</li><li>други патологично натрупани вещества.</li></ul><h2>Обобщение</h2><p>Гломерулните заболявания се проявяват морфологично главно чрез <strong>хиперцелуларност</strong>, <strong>задебеляване на капилярната стена и базалната мембрана</strong>, както и чрез <strong>хиалинизация и склероза</strong>. Тези промени могат да бъдат разграничени и уточнени чрез комплексно биопсично изследване, включващо светлинна микроскопия, имунофлуоресценция, електронна микроскопия и хистохимия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 68. Гломерулопатии. Клинична манифестация, патогенеза на гломерулната увреда. Остър постстрептококов гломерулонефрит.</h1><h2>Гломерулопатии</h2><p><strong>Гломерулопатиите</strong> са заболявания с първично увреждане на <strong>гломерулите</strong>. Терминът е по-точен от „гломерулонефрити“, защото не при всички гломерулни увреждания има възпалителна компонента, макар че понякога двата термина се използват като синоними.</p><p>Класификацията им се основава на <strong>клиничните и морфологичните промени</strong>, патогенетичните механизми, отговора към терапията и прогнозата.</p><p>Най-често гломерулопатиите са <strong>имунологично медиирани</strong>, със симетрично засягане на бъбреците и <strong>стерилна урина</strong>.</p><p>За диагностика е необходима <strong>бъбречна кор-биопсия</strong>, като материалът се изследва със светлинна микроскопия и <strong>имунофлуоресценция</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Гломерулопатии</h2><p>Гломерулопатиите могат да се класифицират и според <strong>топографията на увреждането</strong>:</p><ul><li><strong>интракапилярни</strong> — засягат мезангиума и ендотела;</li><li><strong>интеркапилярни</strong> — засягат предимно мезангиума;</li><li><strong>екстракапилярни</strong> — засягат Баумановото пространство.</li></ul><h3>Основни термини</h3><ul><li><strong>Дифузен</strong> означава засягане на почти всички гломерули — над 80%.</li><li><strong>Фокален</strong> — засяга се част от гломерулите, обикновено над 20%.</li><li><strong>Глобален</strong> — засегната е цялата структура на отделния гломерул.</li><li><strong>Сегментен</strong> — засегната е само част от гломерула.</li><li><strong>Мезангиален</strong> — процесът засяга предимно мезангиума.</li><li><strong>Епимембранозно засягане</strong> — имунните комплекси се отлагат между базалната мембрана и подоцитите.</li><li><strong>Синехии</strong> — сраствания между гломерулни капиляри или между капилярите и париеталния лист на Баумановата капсула.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патогенеза на гломерулното увреждане</h2><p>Гломерулните увреждания най-често са <strong>имунологично медиирани</strong>. Основните механизми са свързани с отлагане или образуване на имунни комплекси и активация на комплемента.</p><h3>Улавяне на готови имунни комплекси</h3><p>Имунните комплекси обикновено не са от бъбречен произход. В изграждането им могат да участват <strong>бактериални, вирусни или ДНК антигени</strong>.</p><p>Те се отлагат в бъбрека поради неговата филтрационна функция. Депозитите могат да бъдат <strong>субендотелни, субепителни или мезангиални</strong>. При имунофлуоресценция дават <strong>грануларно светене</strong>, а при електронна микроскопия се виждат като електронноплътни отлагания.</p><p>Този механизъм може да бъде свързан с възпалителни промени, например при <strong>остър дифузен пролиферативен гломерулонефрит</strong>, но може да протече и без изразено възпаление, както при <strong>мембранозната гломерулопатия</strong>.</p><h3>Образуване на комплекси in situ</h3><p>Първо се имплантира антиген по хода на гломерулните структури, след което към него се свързват антитела. Отлагането обикновено е <strong>субепително</strong>.</p><p>И тук имунофлуоресценцията е <strong>грануларна</strong>, а при електронна микроскопия се виждат електронноплътни депозити.</p><h3>In situ свързване на антитяло с антиген</h3><p>При този механизъм антигенът е част от самата <strong>гломерулна базална мембрана</strong>. Антителата се разпределят равномерно по хода на базалната мембрана, поради което имунофлуоресценцията е <strong>линеарна</strong>.</p><p>Този механизъм причинява тежки структурни увреждания. Класически пример е <strong>синдромът на Goodpasture</strong>.</p><h3>Алтернативно активиране на комплемента</h3><p>При част от болните с плътни депозити има циркулиращи антитела, наречени <strong>C3 нефритен фактор (C3NeF)</strong>. Той активира комплемента по <strong>алтернативен път</strong>.</p><p>Независимо от начина на активация, крайният резултат е образуване на <strong>мембраноатакуващ комплекс (MAC)</strong>. Той причинява цитолиза, стимулира мезангиалните клетки да продуцират медиатори и уврежда гломерулната базална мембрана. Така тя може да придобие нови антигенни свойства и да стане мишена на допълнителни антитела.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Основни групи гломерулни заболявания</h2><p>Най-общо гломерулните заболявания се разделят на:</p><ul><li><strong>първични гломерулопатии</strong>;</li><li><strong>системни заболявания с въвличане на гломерулите</strong>;</li><li><strong>наследствени нарушения</strong>, които също са свързани с първично гломерулно засягане.</li></ul><h2>Класификация на първичните гломерулонефрити</h2><ul><li><strong>Остър дифузен пролиферативен гломерулонефрит</strong></li><ul><li>постстрептококов</li><li>непостстрептококов</li></ul><li><strong>Бързо прогресиращ / полулунен гломерулонефрит</strong></li><li><strong>Мембранозна гломерулопатия</strong></li><li><strong>Болест на минималните изменения</strong></li><li><strong>Фокална сегментна гломерулосклероза</strong></li><li><strong>Мембранопролиферативен гломерулонефрит</strong></li><li><strong>IgA нефропатия</strong></li><ul><li>болест на Berger</li></ul><li><strong>Хроничен гломерулонефрит</strong></li></ul><table style=\"text-align: center\"><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Заболяване</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Светлинна микроскопия</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Имунофлуоресценция</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Електронна микроскопия</span></strong></td></tr><tr><td><strong>Остър дифузен пролиферативен ГН</strong></td><td><strong>Дифузна пролиферация и неутрофили</strong></td><td>IgG и C3 по БМ и мезангиума, грануларно светене</td><td><strong>Субепителни „humps“ / гърбици</strong></td></tr><tr><td><strong>Бързо прогресиращ / полулунен ГН</strong></td><td><strong>Полулуния </strong>— париетални клетки, моноцити и левкоцити</td><td>Зависи от типа</td><td>Понякога субепителни депозити; разкъсване на БМ</td></tr><tr><td><strong>Мембранозна гломерулопатия</strong></td><td><strong>Дифузно задебеляване на капилярната стена</strong></td><td>Грануларни IgG и C3 дифузно</td><td>Субепителни депозити</td></tr><tr><td><strong>Болест на минималните изменения</strong></td><td>Нормални гломерули</td><td>Негативна</td><td><strong>Загуба/сливане на крачетата на подоцитите</strong></td></tr><tr><td><strong>Фокална сегментна гломерулосклероза</strong></td><td>Фокална и сегментна склероза и хиалиноза</td><td>Фокално IgM и C3</td><td>Загуба на крачетата на подоцитите</td></tr><tr><td><strong>Мембранопролиферативен ГН</strong></td><td>Мезангиална пролиферация, задебелена БМ, разцепване</td><td>Тип I: IgG, C3, C1q, C4; Тип II: C3</td><td>Тип I: субендотелни депозити; Тип II: плътни депозити</td></tr><tr><td><strong>IgA нефропатия / болест на Berger</strong></td><td>Фокална пролиферация, разширен мезангиум</td><td>IgA, често с IgM и C3 в мезангиума</td><td>Мезангиални електронноплътни депозити</td></tr><tr><td><strong>Хроничен ГН</strong></td><td>Хиалинизирани гломерули</td><td>Грануларно или негативно</td><td>Неспецифични промени</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър дифузен пролиферативен гломерулонефрит</h2><p>Протича с <strong>нефритен синдром</strong>.</p><h3>Честота и етиология</h3><p>Заболяването засяга най-често деца между <strong>3–7 години</strong>, но се среща и при възрастни, по-често мъже.</p><p>Най-чест причинител са <strong>β-хемолитични стрептококи от група А</strong>, особено тип 12 и други „нефритогенни“ щамове. Освен тях могат да участват и други бактерии, вируси и паразити — пневмококи, клебсиела, стафилококи, причинители на Грам-отрицателен сепсис, менингококи, гонококи, луес, бруцелоза, епидемичен паротит, хепатит B и др.</p><h3>Клиника</h3><p>Началото е около <strong>10 дни след инфекция</strong> — най-често „болно гърло“, пиодермия или ранева инфекция. Проявява се с неразположение, гадене, <strong>олигурия</strong>, кафеникава урина поради <strong>хематурия</strong>, лека до умерена <strong>протеинурия</strong> (до 1 g/24 h) и отоци по лицето, клепачите и ръцете (у деца - и асцит).</p><p>Установява се и умерена <strong>хипертония</strong>, главно с повишаване на диастолното налягане.</p><h3>Макроскопски</h3><p>При редките смъртни случаи бъбреците са умерено увеличени, отпуснати, с гладка повърхност и широка бледа кора. При хеморагична форма кората е изпъстрена с тъмночервени точици — кръвоизливи в гломерулите и каналчетата.</p><h3>Микроскопски</h3><p>Въпреки добрата прогноза хистологичните промени са изразени. <strong>Дифузно са засегнати всички бъбречни телца</strong>. Гломерулите са уголемени, а уринарните пространства са стеснени и могат да съдържат еритроцити.</p><p>Гломерулите са анемизирани, но <strong><u>хиперцелуларни</u></strong>. Налице е пролиферация на <strong>мезангиалните клетки</strong>, като в една мезангиална ос могат да се открият три и повече ядра. Това подчертава <strong><u>лобуларността</u></strong> на гломерула.</p><p>Ендотелните клетки са силно оточни и стесняват капилярните просвети. В капилярите обикновено липсват еритроцити, но се откриват множество <strong><u>неутрофили</u></strong>, моноцити и еозинофили, особено при <strong>ексудативната форма</strong>.</p><p>Базалната мембрана не е задебелена. При трихромно оцветяване по <strong>Masson</strong> имунните комплекси могат да се видят като фини червеникави зрънца по субепителната ѝ повърхност. В мезангиума и капилярните просвети може да има <strong>фибрин</strong>.</p><p>Като тежко усложнение могат да възникнат <strong>сегментни тромбози</strong> и некрози на капилярните бримки — <strong>некротизиращ гломерулонефрит</strong>.</p><p>Още в края на първата седмица може да се наблюдава огнищна и сегментна <strong>екстракапилярна пролиферация</strong> под форма на <strong>полулуния</strong> в Баумановите пространства. Тези полулуния са с еднаква степен на зрелост, за разлика от дифузните полулуния с различна давност при бързопрогресиращия гломерулонефрит.</p><h3>Имуноморфология</h3><p>Дифузният ендокапилярен пролиферативен гломерулонефрит има <strong>имунокомплексна природа</strong>. По хода на гломерулната базална мембрана и в мезангиума се установява <strong>грануларна флуоресценция</strong> за <strong>IgG, C3 и C1q</strong>.</p><p>В кръвта се откриват повишени титри на антистрептококови антитела, понижен серумен <strong>C3</strong> и криоглобулини в острата фаза. Циркулиращи имунни комплекси се установяват само в около 50% от случаите.</p><h3>Електронна микроскопия</h3><p>Установяват се <strong>електронноплътни депозити</strong>, разположени субепително, в самата базална мембрана и по-рядко в мезангиума.</p><p>Характерни са т.нар. <strong>„гърбици“</strong> — неравномерно разположени субподоцитни депозити, по-едри от тези при мембранозната нефропатия. Подоцитните педикулите се разстилат над тях и ги обхващат като <strong>„корона“</strong>.</p><p>Могат да се видят левкоцити, прилепени към оголени от ендотела участъци на капилярната стена. В по-късните стадии се увеличава <strong>мезангиалният матрикс</strong>.</p><h3>Еволюция и прогноза</h3><p>Над <strong>95% от децата</strong> със следстрептококов гломерулонефрит оздравяват клинично, често със затихващ остатъчен уринарен синдром. При възрастни прогнозата е по-неблагоприятна.</p><p>Клетъчната пролиферация може да регресира, но често остава лека <strong>мезангиална хиперплазия и склероза</strong>. Тази картина се означава като резорбиращ се слединфекциозен, или <strong>мезангиопролиферативен гломерулонефрит</strong>.</p><p>Около <strong>1%</strong> от случаите завършват със смърт от остра сърдечна или остра бъбречна недостатъчност. Около <strong>1–2%</strong> преминават в полулунен гломерулонефрит, а малка част прогресират до склерозиращ гломерулонефрит.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 69. Гломерулопатии. Морфологична класификация. Подостър гломерулонефрит. Мезангиопролиферативен гломерулонефрит.</h1><p>Уводът, патогенезата и класификацията са същите от тема 68.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Подостър / бързопрогресиращ полулунен гломерулонефрит</h2><p><em>Бързопрогресиращият гломерулонефрит е клинико-морфологичен синдром, който обикновено е </em><em>усложнение на друга гломерулопатия</em>, но макар и рядко може да възникне и без изяснена причина.</p>Протича с <strong>нефритен синдром</strong> и бързо води до <strong>остра бъбречна недостатъчност</strong>. Характерен белег е образуването на <strong>полулуния</strong> в Баумановото пространство.<h4>Типове</h4><p>Обикновено този гломерулонефрит възниква като усложнение на слединфекциозен дифузен ендокапилярен гломерулонефрит или на системни заболявания.</p>Различават се няколко типа според патогенетичния механизъм:<p><strong>Тип I — антибазалномембранен\n</strong>Свързан е с антитела срещу гломерулната базална мембрана. Може да бъде <strong>идиопатичен</strong> или част от <strong>синдрома на Goodpasture</strong>.</p><p><strong>Тип II — имунокомплексен\n</strong>Причинява се от отлагане на имунни комплекси. Среща се при <strong>СЛЕ</strong>, постинфекциозен гломерулонефрит, пурпура на Henoch-Schönlein / IgA-нефропатия и др.</p><p><strong>Тип III — ANCA-асоцииран\n</strong>Свързан е с <strong>антинеутрофилни цитоплазмени антитела (ANCA)</strong>. Може да бъде идиопатичен или да се наблюдава при <strong>грануломатоза на Wegener</strong> и микроскопски полиангиит.</p><h3>Патогенеза</h3><p>Следстрептококовият и лупусният <strong>бързопрогресиращ гломерулонефрит</strong> се развиват чрез <strong>улавяне на имунни комплекси</strong>.</p><p>Само в около <strong>10%</strong> от случаите се наблюдава <strong>линеарна имунофлуоресценция</strong>, при която антигенът е самата <strong>гломерулна базална мембрана</strong> по цялото ѝ протежение. Това се среща при <strong>синдром на Goodpasture</strong> или при идиопатичен бързопрогресиращ гломерулонефрит.</p><p>В около половината от идиопатичните случаи се предполага участие на <strong>антинеутрофилни цитоплазмени антитела (ANCA)</strong>. Те увреждат левкоцитите, а освободените литични ензими атакуват <strong>гломерулната базална мембрана</strong>.</p><h3>Морфогенеза</h3><p>Процесът започва интракапилярно, но основната хистологична сцена е <strong>Баумановото пространство</strong>, където се образуват екстракапилярни сърповидни клетъчни пролиферати — <strong>полулуния</strong>.</p><p><strong>MAC</strong>, привлечените левкоцити и моноцити, както и сегментните тромбози и некрози, водят до разкъсване на <strong>гломерулната базална мембрана</strong>. През тези разкъсвания в уринарното пространство попада <strong>фибриноген</strong>, който се превръща във <strong>фибрин</strong>.</p><p>Отлагането на фибрин е ключов момент в образуването на полулунията. Той привлича моноцити, които навлизат в Баумановото пространство и пролиферират. Отделените от тях монокини и растежни фактори стимулират и пролиферацията на <strong>париеталните клетки на Баумановата капсула</strong>.</p><p>Полулунията се изграждат основно от <strong>моноцити и париетални клетки</strong>. По-късно през пробиви в базалната мембрана навлизат перигломеруларни фибробласти, които участват в образуването на базалномембраноподобен материал и <strong>колаген</strong>.</p><p>С „узряването“ си полулунията притискат гломерулните капиляри и водят до <strong>склероза на целия гломерул</strong>.</p><h3>Макроскопски</h3><p>Бъбреците са силно увеличени — около <strong>250–300 g всеки</strong>, бледи и отпуснати — т.нар. <strong>„големи бели бъбреци“</strong>.</p><p>Когато коровата повърхност е изпъстрена с точковидни кръвоизливи, картината се означава като <strong>„големи пъстри бъбреци“</strong>. На срез в широката кора могат да се видят жълти петна и ивички, свързани с белтъчна и мастна инфилтрация на каналчевия епител.</p><h3>Микроскопски</h3><p>В <strong>70–80% от бъбречните телца</strong> се образуват екстракапилярни <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-10/text-editor-images/2026/05/1778411095522-image.png &quot;width=100%&quot;)\" id=\"note-1778411097335-0\">полулуния</span></strong> от струпвания на клетки в Баумановото пространство. Те обхващат голяма част от обиколката на Баумановата капсула и притискат гломерулните капиляри.</p><p>За разлика от постстрептококовия гломерулонефрит, тук полулунията са <strong>дифузни и с различна давност</strong>.</p><p>В гломерулите се установяват:</p><ul><li><strong>сегментни тромбози</strong></li><li>огнищна <strong>фибриноидна некроза</strong></li><li>левкоцитна инфилтрация</li><li>лека мезангиална хиперплазия</li><li>колабирани капиляри</li><li>множество <strong>синехии</strong> между капилярните бримки и полулунията</li></ul><p>В началото полулунията са <strong>клетъчни</strong>, по-късно стават <strong>фиброепителни</strong>, а процесът завършва с <strong>глобална склероза</strong> на бъбречните телца.</p><p>При лупусна генеза могат да се наблюдават <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-10/text-editor-images/2026/05/1778411134660-image.png &quot;width=100%&quot;)\" id=\"note-1778411135738-1\">телени бримки</span>“</strong> — капиляри с отворен лумен и силно задебелена стена поради отложени имунни комплекси.</p><h3>Имунофлуоресценция</h3><p>При антибазалномембранния тип се наблюдава <strong>линеарно светене</strong> по гломерулната базална мембрана.</p><p>При имунокомплексния тип светенето е <strong>грануларно</strong>, според мястото на отлагане на имунните комплекси.</p><p>При ANCA-асоциираните форми имунните депозити са оскъдни или липсват — т.нар. <strong>pauci-immune</strong> картина.</p><p>Фибринът в Баумановото пространство може да свети силно, което отразява разкъсването на базалната мембрана и преминаването на фибриноген.</p><h3>Прогноза</h3><p>Прогнозата е тежка. Без лечение болните развиват бъбречна недостатъчност за <strong>3–12 месеца</strong>.</p><p>Дори нефректомия и бъбречна трансплантация не подобряват значително прогнозата, защото бързопрогресиращият гломерулонефрит може да <strong>рецидивира в трансплантата</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Мезангиокапилярен /мембранопролиферативен гломерулонефрит</h2><p>Мезангиокапилярният гломерулонефрит е протрахирано протичащ <strong>дифузен гломерулонефрит</strong> с пролиферация на мезангиума. Мезангиумът навлиза в капилярните стени и ги <strong>разслоява</strong>, поради което те са задебелени и съдържат <strong>електронноплътни имунни депозити</strong>.</p><h3>Разпределение</h3><p>Различават се два основни типа, които вероятно представляват отделни заболявания.</p><p><strong>Тип I</strong> е по-чест — около <strong>75%</strong> от случаите. Среща се най-често при момичета в пубертетна възраст.</p><p><strong>Тип II</strong> засяга по-често момчета и млади пациенти. Нарича се още <strong>болест на плътните депозити</strong>.</p><h3>Морфогенеза</h3><p>При <strong>тип I</strong> се активира комплементът по <strong>класическия път</strong>.</p><p>При <strong>тип II</strong> се установява <strong>хипокомплементемия C3</strong> при нормални стойности на C1q и C4. В кръвта се открива <strong>C3 нефритен фактор (C3NeF)</strong> — IgG антитяло срещу алтернативната C3-конвертаза. То стабилизира конвертазата и активира комплемента по <strong>алтернативния път</strong>.</p><p>Хипокомплементемията може да предхожда с месеци появата на плътни депозити в гломерулната базална мембрана.</p><h3>Микроскопски</h3><p>Независимо от типа, бъбречните телца са <strong>уголемени</strong>, а в началото Баумановите пространства са стеснени.</p><p>Мезангиалните зони във всички гломерули са <strong>разширени и хиперцелуларни</strong>, с повече от три мезангиални клетки, увеличен матрикс и лека левкоцитна инфилтрация. Когато мезангиалната пролиферация ясно подчертава гломерулните лобули, формата се означава като <strong>лобуларен гломерулонефрит</strong>.</p><p>Ендотелът също пролиферира, а капилярните просвети са стеснени. В напреднали стадии в мезангиалните оси могат да се формират <strong>склеротични възелчета</strong>.</p><p>При <strong>тип I</strong> с PAS-оцветяване или сребърна импрегнация се вижда <strong>раздвояване на базалната мембрана</strong>, наподобяващо „трамвайни релси“ / „железопътна линия“.</p><p>При <strong>тип II</strong> капилярните стени са силно задебелени, еозинофилни и ригидни поради плътните депозити.</p><h3>Електронна микроскопия</h3><p><strong>Тип I:\n</strong>Ултраструктурно се установяват <strong>електронноплътни субендотелни депозити</strong> в <em>lamina rara interna</em> на гломерулната базална мембрана. Към тях се насочват израстъци на <strong>мезангиалните клетки</strong>, които проникват между ендотела и базалната мембрана — <strong>мезангиална интерпозиция</strong>.</p><p>Около тези мезангиални израстъци се отлага базалномембраноподобен матрикс. Той наподобява гломерулна базална мембрана, но <strong>няма нормалната ѝ трислойна структура</strong>. Затова старото название <strong>„мембранопролиферативен“</strong> е неточно — не става дума за истинско размножаване на базалната мембрана, а за мезангиална интерпозиция и отлагане на матрикс.</p><p>При протеинурия се наблюдава <strong>изглаждане на подоцитните педикулите</strong>.</p><p>Имунофлуоресцентно се открива фино <strong>грануларно отлагане на C3</strong>, което очертава лобулираността на гломерула. Почти винаги се намира <strong>IgG</strong>, по-рядко <strong>IgM</strong> и <strong>IgA</strong>. Имунните депозити могат да се откриват както по капилярните стени, така и в мезангиума.</p><p><strong>Тип II:\n</strong>\"Тип II се означава като <strong>болест на плътните депозити</strong>. При електронна микроскопия по хода на <em>lamina densa</em> се виждат широки, лентовидни <strong>електронноплътни интрамембранозни депозити</strong> с неизвестен състав. Те могат да бъдат почти непрекъснати по протежение на базалната мембрана. Мезангиална интерпозиция също може да се наблюдава.</p><p>Имунофлуоресцентно се установява предимно <strong>C3</strong>, с грануларно или линеарно отлагане. Обикновено липсват <strong>IgG, C1q и C4</strong>, което отразява активация на комплемента по <strong>алтернативния път</strong>.</p><h3>Имуноморфология</h3><p>При <strong>тип 1</strong> се открива фино <strong>грануларно отлагане на C3</strong>, което очертава лобулираността на гломерула. Почти винаги се намира <strong>IgG</strong>, по-рядко <strong>IgM</strong> и <strong>IgA</strong>. Имунните депозити могат да се откриват както по капилярните стени, така и в мезангиума.</p><p>При<strong> тип 2</strong> се установява предимно <strong>C3</strong>, с грануларно или линеарно отлагане. Обикновено липсват <strong>IgG, C1q и C4</strong>, което отразява активация на комплемента по <strong>алтернативния път</strong>.</p><h3>Прогноза</h3><p>Мезангиокапилярният гломерулонефрит обикновено <strong>прогресира бавно</strong>. В около <strong>50% от случаите</strong> за 10 години води до <strong>хронична бъбречна недостатъчност</strong>.</p><p>Лечението често има незадоволителен ефект, особено при <strong>II тип — болест на плътните депозити</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\"><span style=\"color: rgb(255, 192, 0)\">Допълнителни гломерулопатии</span></h1><p>Може да се паднат на теста или клинични задачи</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Синдром на Goodpasture</h2><p><strong>Синдромът на Goodpasture</strong> е автоимунен <strong>белодробно-бъбречен синдром</strong>, при който има генетично предразположение.</p><h3>Етиология</h3><p>Антигенът е неколагеновата част на <strong>α-веригата на колаген тип IV</strong>, който участва в строежа както на <strong>алвеолната</strong>, така и на <strong>гломерулната базална мембрана</strong>.</p><p>Сенсибилизацията към алвеолните мембрани може да бъде провокирана от вируси или вдишване на въглеводородни разтворители и да доведе до <strong>антибазалномембранен гломерулонефрит</strong>.</p><h3>Клиника</h3><p>Заболяването започва с белодробни прояви — <strong>хемоптое</strong> или животозастрашаващи белодробни кръвоизливи, особено при млади мъже пушачи. По-късно се развива <strong>бъбречна недостатъчност</strong>.</p><h3>Морфология</h3><p>Установява се <strong>некротизиращ интерстициален пневмонит</strong> с последваща <strong>хемосидероза</strong>, съчетан с <strong>полулунен гломерулонефрит</strong>.</p><p>В двата органа по базалните мембрани се доказва <strong>линеарна имунофлуоресценция</strong> за <strong>IgG и C3</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Болест на минималните изменения</h2><p><strong>Синоними:</strong> липоидна нефроза, болест на подоцитните крачета.</p><p>Заболяването протича с <strong>нефротичен синдром</strong> и високоселективна протеинурия — губят се главно нискомолекулни белтъци като <strong>албумин</strong> и трансферин. Обикновено няма <strong>хематурия</strong> и <strong>артериална хипертония</strong>. Най-често засяга момчета между <strong>2–6 години</strong>.</p><h3>Етиология и патогенеза</h3><p>Предполага се <strong>имунна генеза</strong>, въпреки че в гломерулите не се откриват имунни депозити. Често се предшества от респираторни инфекции или имунизации и се повлиява добре от кортикостероиди.</p><p>Основният механизъм е увреждане на <strong>подоцитите</strong> и нарушаване на електростатичната бариерна функция на гломерулната базална мембрана.</p><h3>Макроскопски</h3><p>Бъбреците са почти двойно увеличени, отпуснати, с гладка повърхност. Кората е широка, бледа и прошарена с нежни жълтеникави петънца.</p><h3>Микроскопски</h3><p>При светлинна микроскопия гломерулите изглеждат почти нормални. <strong>Базалната мембрана не е задебелена.</strong> В проксималните каналчета има хиалинни гранули и фини липидни капки, свързани със засилена белтъчна и липидна реабсорбция.</p><p><strong>Имунофлуоресценцията е негативна.</strong></p><h3>Електронна микроскопия</h3><p>Патогномонична е <strong>загубата / сливането на подоцитните педикулите</strong>. Подоцитите са оточни, вакуолизирани и се разстилат върху запазената базална мембрана. Може да има и <strong>микровилозна трансформация</strong>.</p><h3>Прогноза</h3><p>В около <strong>90%</strong> от случаите настъпва ремисия след кортикостероидна терапия. Рецидивите обикновено са с добра прогноза, особено след пубертета. Рядко се срещат стероидрезистентни случаи, които могат да прогресират до <strong>хронична бъбречна недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Огнищна сегментна гломерулосклероза</h2><p><strong>Огнищната сегментна гломерулосклероза</strong> е причина за част от случаите на <strong>нефротичен синдром</strong> — около 10% при деца и 15% при възрастни. Допуска се, че може да представлява късен стадий на <strong>болестта на минималните изменения</strong>.</p><h3>Клиника</h3><p>Характерна е за <strong>затегнато протичащ, стероидрезистентен нефротичен синдром</strong>. Може да се съчетае с <strong>неселективна протеинурия</strong>, хематурия и намалена гломерулна филтрация.</p><p>Измененията са:</p><ul><li><strong>огнищни</strong> — засягат под половината гломерули;</li><li><strong>сегментни</strong> — засягат само части от отделния гломерул.</li></ul><h3>Микроскопски</h3><p>Промените започват най-често в <strong>юкстамедуларните гломерули</strong>. В засегнатите сегменти капилярите са <strong>колабирани и хиалинизирани</strong>.</p><p>В останалите гломерули може да има само лека мезангиална хиперплазия. Тубулите са атрофични, а интерстициумът фиброзира.</p><h3>Имуноморфология и ЕМ</h3><p>В склерозираните сегменти се откриват <strong>IgM и C3</strong>.</p><p>Електронномикроскопски най-характерно е <strong>отлепването на вакуолизирани подоцити</strong> от базалната мембрана. Между тях и оголената базална мембрана може да се оформи просветлен процеп.</p><h3>Прогноза</h3><p>При прогресия процесът става <strong>глобален и дифузен</strong>. Около половината от случаите за 10 години прогресират до <strong>терминален бъбрек</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>IgA-нефропатия</h2><p><strong>Синоним:</strong> болест на Berger.</p><p><strong>IgA-нефропатията</strong> е първичен пролиферативен интеркапилярен гломерулонефрит с отлагане на <strong>IgA в мезангиума</strong>. Вторична IgA-нефропатия може да се развие при пурпура на Schönlein-Henoch, <strong>СЛЕ</strong> и хронично чернодробно заболяване.</p><h3>Честота и клиника</h3><p>Засяга предимно <strong>мъже между 15–30 години</strong>.</p><p>Обикновено се развива след лигавични инфекции на респираторния, гастроинтестиналния или уринарния тракт. Само <strong>1–2 дни</strong> след инфекцията се появява макро- или микрохематурия, която спонтанно отзвучава за около седмица, но рецидивира след месеци.</p><p>Придружаващата протеинурия може да прогресира до <strong>нефротичен синдром</strong>.</p><h3>Етиология и морфогенеза</h3><p>Заболяването е свързано с <strong>генетичен или придобит дефект в имунната регулация</strong>. Характерни са дифузни мезангиални отложения на <strong>IgA и C3</strong>, като преобладава активация на комплемента по <strong>алтернативния път</strong>.</p><p>Поради сходните бъбречни промени и IgA-отлагания в малките съдове на кожата при пурпура на Schönlein-Henoch, се допуска, че двете състояния могат да са прояви на единен системен процес.</p><h3>Микроскопски</h3><p>Промените се оценяват според степента на <strong>мезангиална пролиферация и склероза</strong>, наличие на полулуния, тубулна атрофия и интерстициална клетъчна инфилтрация.</p><h3>Имуноморфология и ЕМ</h3><p>Имунофлуоресцентната находка е патогномонична: <strong>IgA и C3</strong> се откриват във всички мезангиални оси на всички гломерули. <strong>IgG</strong> се намира в част от биопсиите.</p><p>Електронномикроскопски се вижда увеличен брой мезангиални клетки, увеличен мезангиален матрикс и различни по големина <strong>електронноплътни мезангиални депозити</strong>.</p><h3>Прогноза</h3><p>Възможна е <strong>остра бъбречна недостатъчност</strong> поради тубулотоксичния ефект на резорбирания хемоглобин. Заболяването прогресира бавно и при около половината болни за <strong>20 години</strong> води до бъбречна недостатъчност.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Мембранозна нефропатия</h2><p><strong>Синоним:</strong> мембранозен гломерулонефрит.</p><p>Мембранозната нефропатия е най-честата причина за <strong>нефротичен синдром при възрастни</strong>. Характеризира се с <strong>дифузно задебеляване на капилярните стени</strong> във всички гломерули, без изразена клетъчна пролиферация.</p><h3>Етиология и морфогенеза</h3><p>Заболяването е <strong>имунно медиирано</strong>. Имунните депозити са разположени <strong>епимембранозно / субподоцитарно</strong>, с грануларно отлагане на <strong>IgG и C3</strong>.</p><p>В около 1/4 от случаите е <strong>вторична</strong> проява при инфекции, неоплазми, системен лупус, ревматоиден артрит или медикаменти като пенициламин и каптоприл.</p><p>При идиопатичната форма имунните комплекси вероятно се образуват <strong>in situ</strong> чрез антитела срещу повърхностни антигени на подоцитните крачета.</p><p>Понеже депозитите са извън базалната мембрана, тя действа като преграда за левкоцити и мезангиум — затова <strong>липсват изразена инфилтрация и пролиферация</strong>.</p><h3>Морфология</h3><p>Морфологичните промени са стадийни.</p><p><strong>I стадий:</strong></p><p>Светлинномикроскопски измененията са минимални. Имунофлуоресцентно има фино зърнеста, псевдолинеарна флуоресценция за <strong>IgG и C3</strong> по уринарната повърхност на базалната мембрана. Електронномикроскопски се виждат дребни епимембранозни депозити, подредени като „броеница“.</p><p><strong>II стадий:</strong></p><p>Базалната мембрана е огнищно задебелена. При Masson депозитите изглеждат като фини червени гранулки. При сребърна импрегнация се виждат характерни <strong>„шипчета“</strong>, изхождащи от lamina densa, между които са разположени имунните депозити.</p><p><strong>III стадий:</strong></p><p>Подоцитите отлагат базалномембраноподобен материал, който свързва шипчетата и обгръща депозитите. Базалната мембрана става <strong>дифузно задебелена</strong>, а капилярите са ригидни и стеснени.</p><p><strong>IV стадий:</strong></p><p>Имунните комплекси постепенно се резорбират и базалната мембрана изглежда като <strong>„проядена от молци“</strong>. С времето процесът може да завърши с <strong>гломерулосклероза</strong>. В каналчетата се откриват белтъчни гранули, а интерстициумът фиброзира.</p><h3>Прогноза</h3><p>Протича бавно. Началната протеинурия често се комбинира с хематурия.</p><p>Около <strong>20%</strong> от болните достигат пълна ремисия. Протеинурията персистира при около <strong>60%</strong>, а около <strong>40%</strong> развиват <strong>хронична бъбречна недостатъчност</strong>. Малка част прогресират до склерозиращ гломерулонефрит.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Дифузен склерозиращ гломерулонефрит</h2><p><strong>Синоними:</strong> гломерулонефритна нефросклероза, „хроничен“ гломерулонефрит.</p><p>Представлява <strong>краен общ път на първичните гломерулонефрити</strong>.</p><ul><li><strong>Постстрептококов гломерулонефрит</strong> → около <strong>5%</strong> прогресират до хроничен ГН.</li><li><strong>Мембранозен гломерулонефрит</strong> → около <strong>40%</strong> прогресират до хроничен ГН.</li><li><strong>Фокална сегментна гломерулосклероза</strong> → около <strong>10 години</strong> до развитие на хроничен ГН.</li><li><strong>Мембранопролиферативен гломерулонефрит</strong> → около <strong>50%</strong> за <strong>10 години</strong> прогресират до хроничен ГН.</li><li><strong>IgA нефропатия</strong> → около <strong>50%</strong> за <strong>20 години</strong> прогресират до хроничен ГН.</li></ul><p>В този стадий първичното заболяване губи морфологичната си специфичност поради напреднала склероза, а клинично доминира <strong>хронична бъбречна недостатъчност</strong>.</p><p>Често първата биопсия се прави едва когато бъбреците вече са изчерпали компенсаторните си възможности. Затова дифузният склерозиращ гломерулонефрит може да бъде първа поставена диагноза, но не е първично заболяване.</p><h3>Макроскопски</h3><p>Двата бъбрека са <strong>симетрично силно умалени</strong>, около <strong>50 g всеки</strong>. Декапсулацията е умерено затруднена, а повърхността е светлокафеникава и <strong>дребнозърнеста</strong>.</p><p>На срез кората е силно стеснена, медулата също е атрофична. В кортико-медуларната зона се виждат склерозирани дъговидни артерии. Около легенчетата компенсаторно разраства мастна тъкан, а лигавицата на пиелона е непроменена.</p><h3>Микроскопски</h3><p>Само в единични гломерули могат да се открият остатъчни белези от първичното заболяване. Повечето гломерули са <strong>хиалинизирани, безклетъчни и с намалени размери</strong>.</p><p>Хиалинът е <strong>PAS-позитивен</strong> и се дължи на улавяне на плазмени протеини, натрупване на мезангиален матрикс и колаген. Около някои хиалинизирани гломерули има лимфоидни инфилтрати.</p><p>Нефроните със засегнати гломерули загиват, а на тяхно място в кората и медулата разраства съединителна тъкан. Въпреки това единични гломерули и техните каналчета могат да останат незасегнати и дори да хипертрофират, поддържайки минимална бъбречна функция.</p><p>Поради развилата се артериална хипертония се наблюдава и <strong>вторична артериолосклероза</strong> на бъбречните съдове.</p><h3>Прогноза</h3><p>Дифузният склерозиращ гломерулонефрит води до <strong>терминална хронична бъбречна недостатъчност</strong> и налага <strong>хронична хемодиализа</strong> или <strong>бъбречна трансплантация</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 70. Ендемична и аналгетична нефропатия. Морфологична характеристика, усложнения.</h1><h2>Балканска ендемична нефропатия</h2><p><strong>Балканската ендемична нефропатия</strong> е хронично тубулоинтерстициално заболяване, което прогресира до тежка <strong>нефросклероза</strong>, без артериална хипертония и нефротичен синдром.</p><p>Често се съчетава с <strong>папиларни тумори на пикочоотводящите пътища</strong>. Има дълъг латентен период и се проявява клинично най-често между <strong>40–60 години</strong>.</p><h3>Честота и разпространение</h3><p>Среща се в <strong>Северозападна България</strong> — Врачанско и около Монтана, както и в съседни райони на Сърбия и Румъния.</p><h3>Етиология</h3><p>Заболяването има подчертан <strong>фамилен характер</strong>. Младежи, които са емигрирали от ендемичния район, могат да развият заболяването по-късно.</p><p>Предполага се <strong>автозомно-доминантно унаследяване</strong> с висока пенетрантност и експресивност на болестния ген. Външни фактори вероятно действат като отключващи.</p><h3>Макроскопски</h3><p>В терминалния стадий двата бъбрека са симетрично и силно умалени — около <strong>20–50 g</strong>, с гладка повърхност.</p><p>На срез кората е силно стеснена, докато атрофията на медулата е по-слабо изразена. В легенчетата и уретерите често се откриват <strong>папиломи и папиларни карциноми</strong>.</p><h3>Микроскопски</h3><p>В напреднал стадий промените са <strong>зонални</strong>. Външната кора е дифузно склерозирана; сред съединителната тъкан липсват каналчета, а гломерулите са напълно хиалинизирани.</p><p>Във вътрешната кора тубулите са <strong>атрофични и дилатирани</strong>, с белтъчни цилиндри в лумените и мастна инфилтрация на епитела. На места има некроза, но се срещат и регенераторни прояви.</p><p>Съдовите склеротични промени са умерени, а интерстициалните лимфоидни инфилтрати са <strong>оскъдни</strong>, въпреки тежестта на уврежданията.</p><h3>Прогноза</h3><p>Прогнозата е неблагоприятна. В ендемичните райони над половината от смъртността от бъбречни заболявания се дължи на <strong>балканска ендемична нефропатия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аналгетична нефропатия</h2><p><strong>Синоним:</strong> Хроничен медикаментозен тубулоинтерстициален нефрит с папиларни некрози.</p><h3>Етиология</h3><p>Развива се при хронична злоупотреба с <strong>аналгетични смеси</strong>, съдържащи фенацетин и производни, аспирин, кофеин и кодеин. Представлява причина за част от случаите на <strong>хронична бъбречна недостатъчност</strong>.</p><h3>Морфогенеза</h3><p>Аналгетичната нефропатия започва с <strong>папиларни некрози</strong>, след които вторично се развива кортикален <strong>тубулоинтерстициален нефрит</strong>.</p><p>Папиларните некрози се дължат на:</p><ul><li>директен нефротоксичен ефект на <strong>фенацетина</strong> върху тубулните и ендотелните клетки;</li><li>исхемично увреждане от <strong>аспирина</strong>, който блокира простагландиновия синтез във вътрешната медула.</li></ul><h3>Макроскопски</h3><p>Двата бъбрека са симетрично намалени. Коровата повърхност е неравна, с широки хлътвания, редуващи се с надигнати възли. Хлътванията съответстват на атрофични корови участъци над некротичните папили.</p><p>Повечето папили са свити, жълто-кафеникави и с некротични изменения в различен стадий. Откъснати папили могат да се открият в легенчето или уретера.</p><h3>Микроскопски</h3><p>Папиларната некроза морфологично отговаря на <strong>анемичен инфаркт</strong>. До кортико-медуларната граница се развива <strong>коагулационна некроза</strong>, а около нея — демаркационна възпалителна инфилтрация.</p><p>В кората се наблюдават:</p><ul><li>атрофия на извитите каналчета на прекъснатите нефрони;</li><li>кръглоклетъчни инфилтрати;</li><li>интерстициална фиброза.</li></ul><p>Ако некротичната папила не се секвестрира, в нея може да настъпи <strong>дистрофично калциране</strong> и дори образуване на костна тъкан. Често се наслагват и възпалителни промени.</p><p>Важен диференциалнодиагностичен белег спрямо хроничния пиелонефрит е <strong>PAS-позитивното задебеляване на базалните мембрани</strong> на малките съдове под преходния епител на папилите и по уринарния тракт — <strong>аналгетична микроангиопатия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 71. Интестициални нефрити – остри и хронични.</h1><p>Интерстициалните нефрити са част от <strong>тубулоинтерстициалните заболявания</strong> — заболявания, при които патологичните изменения започват в <strong>интерстициума и тубулите</strong>.</p><p>При тях се наблюдават:</p><ul><li><strong>намалена концентрационна способност</strong>, водеща до <strong>полиурия</strong> и <strong>никтурия</strong>;</li><li><strong>загуба на соли</strong>;</li><li><strong>метаболитна ацидоза</strong> в тежките случаи.</li></ul><p>Тубулоинтерстициалните заболявания се отличават от гломерулопатиите по липсата на <strong>нефритен</strong> и <strong>нефротичен синдром</strong>.</p><h2>Етиология</h2><p>Тубулоинтерстициалните заболявания могат да се причинят от:</p><ul><li><strong>инфекции</strong>:</li><ul><li>бактерии — остър бактериален нефрит, пиелонефрит с рефлукс;</li><li>вируси;</li><li>паразити;</li><li>микотични инфекции;</li><li>бъбречна туберкулоза;</li></ul><li><strong>токсични фактори</strong>:</li><ul><li>лекарства — остър хиперсензитивен интерстициален нефрит;</li><li>аналгетици;</li><li>тежки метали — олово, кадмий;</li></ul><li><strong>метаболитни нарушения</strong>:</li><ul><li>уратна нефропатия;</li><li>нефрокалциноза;</li><li>хиперкалциемия;</li><li>оксалатна нефропатия;</li><li>хипокалиемична нефропатия;</li><li>амилоидоза, диабет, подагра;</li></ul><li><strong>физични фактори</strong>:</li><ul><li>хронична обструкция на уринарния тракт;</li><li>радиация;</li></ul><li><strong>имунологични реакции</strong> — реакция на отхвърляне на транспланта, болест на Сьогрен, саркоидоза;</li><li><strong>неоплазми</strong> — мултиплен миелом;</li><li><strong>съдови заболявания</strong>;</li><li><strong>Балканска ендемична нефропатия</strong>;</li><li>нефронофтизис / медуларно кистично заболяване;</li><li>идиопатичен интерстициален нефрит.</li></ul><h2>Морфология</h2><p>Доминиращата морфологична проява може да бъде:</p><ol><li><strong>Възпалителни инфилтрати в интерстициума</strong> — например при пиелонефрит.</li><li><strong>Задебеляване на базалните мембрани на тубулите</strong> — при диабет, амилоидоза и отхвърляне на трансплантиран бъбрек.</li><li><strong>Отлагане на абнормни субстанции в тубулите и интерстициума</strong> — калций, амилоид, урати, миеломни протеини и оксалати.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Пиелонефрит</h2><p><strong>Пиелонефритът</strong> е инфекциозно-възпалително заболяване, при което се засягат <strong>легенчето, тубулите и интерстициумът</strong> на бъбрека. Той принадлежи към <strong>тубулоинтерстициалните заболявания</strong> и може да бъде <strong>остър</strong> или <strong>хроничен</strong>.</p><h3>Честота и разпространение</h3><p>Пиелонефритът е най-честото бъбречно страдание у нас. Жените страдат по-често от мъжете поради по-лесното бактериално колонизиране на по-късата уретра. Особено уязвими са в началото на сексуалния живот и по време на бременност.</p><p>Мъжете боледуват по-често в двата възрастови полюса — в ранна детска възраст поради вроден рефлукс и в напреднала възраст поради обструкция от простатна хипертрофия. В зряла възраст те са протектирани в значителна степен от бактерицидния ефект на простатния секрет.</p><h3>Етиология</h3><p><strong>Острият пиелонефрит</strong> е пряка проява на бактериална или микотична инфекция. Най-честите причинители са различни бактерии:</p><ul><li><strong>Escherichia coli</strong>;</li><li>Proteus;</li><li>Klebsiella;</li><li>Enterobacter;</li><li>Staphylococcus aureus;</li><li>Salmonella;</li><li>Pseudomonas.</li></ul><p>Възможни са и микотични причинители — <strong>Candida</strong>, <strong>Aspergillus</strong>.</p><p>От вирусите значение имат <strong>полиома вирус</strong>, <strong>цитомегаловирус</strong> и <strong>аденовирус</strong>. Тази група вирусни инфекции е характерна за трансплантираните бъбреци.</p><p>За възникването на <strong>хроничния пиелонефрит</strong>, освен етиологичните агенти, решаваща роля имат факторите, които способстват за застой на урината:</p><ul><li>анатомични аномалии;</li><li>обструкция на пикочните пътища;</li><li><strong>везикоуретерален рефлукс</strong>;</li><li>литиаза;</li><li>неоплазми;</li><li>уретрална стеноза;</li><li>простатна хипертрофия;</li><li>хронична катетеризация.</li></ul><h3>Патогенеза</h3><p>Инфекциозните агенти достигат бъбречния паренхим най-често по <strong>асцендентен път</strong>, включително лимфогенно от гениталиите, и по-рядко — по <strong>десцендентен / хематогенен път</strong>.</p><h4>Асцендентна инфекция</h4><p>При асцендентната инфекция се засягат първо долните пикочни пътища, а след това инфекцията се възкачва към бъбрека. Тя обикновено протича по следния път:</p><ol><li><strong>Колонизация на уретрата</strong>.</li><li><strong>Адхезия към епитела</strong>.</li><li><strong>Проникване в пикочния мехур</strong> и развитие на цистит, често след катетеризация.</li><li><strong>Везикоуретерален рефлукс</strong> с връщане на инфектирана урина към уретерите и бъбречното легенче.</li><li><strong>Интраренален рефлукс</strong> с навлизане на бактерии в бъбречния паренхим.</li></ol><p>Асцендентната инфекция най-често се дължи на <strong>Грам-отрицателни бактерии</strong>, обитаващи дебелото черво — <strong>E. coli</strong>, Proteus, Klebsiella, Enterobacter и др.</p><p>При асцендентния път обикновено се засягат <strong>горният и долният полюс на бъбрека</strong>.</p><p>Развитието на микроорганизмите се благоприятства от застой на урината при обструкция, атрофия на мехура, бременност, диабетна невропатия и глюкозурия. Бактериурия над <strong>10<sup>5</sup>/ml урина</strong> се означава като <strong>сигнификантна</strong>, тъй като насочва към инфекция на пикочните пътища.</p><p>Наличието на <strong>левкоцитни цилиндри</strong> в урината е важен критерий за засягане на бъбречния паренхим. <strong>Стерилната пиурия</strong> — левкоцитурия без позитивиране на микробните посявки — е съмнителна за туберкулоза.</p><h4>Хематогенна инфекция</h4><p>Хематогенният пиелонефрит се развива при септицемия или инфекциозен ендокардит. По този път причинителите достигат бъбрека чрез кръвта.</p><p>При хематогенния път може да се засегне <strong>целият бъбрек</strong>, като е възможно формиране на <strong>микроабсцеси</strong>. В сравнение с асцендентния пиелонефрит, при хематогенния по-засегната е бъбречната кора, често с формиране на абсцеси.</p><h3>Остър и хроничен пиелонефрит</h3><p><strong>Острият пиелонефрит</strong> се дължи най-често на бактериална или микотична инфекция.</p><p><strong>Хроничният пиелонефрит</strong> също е най-често бактериален. Може да протече с или без <strong>везикоуретерален рефлукс</strong>, както и при наличие на <strong>обструкция</strong>.</p><p>В генезата на рецидивиращия пиелонефрит се предполага участие на протопласти — бактерии с променена форма след загуба на част от стената им, устойчиви на антибиотици и на хипертоничната среда на бъбречната папила.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър пиелонефрит</h2><p><strong>Острият пиелонефрит</strong> е инфекциозно-възпалително заболяване на легенчето, тубулите и интерстициума на бъбрека. Той може да възникне по <strong>асцендентен</strong> или <strong>хематогенен</strong> път и да бъде едностранен или двустранен.</p><h3>Морфология</h3><p>При асцендентните инфекции бъбреците могат да бъдат умерено, понякога и силно увеличени. Декапсулират се лесно. При <strong>асцендентен остър пиелонефрит</strong> лигавицата на легенчето е зачервена и покрита с ексудат. Засягането на двата полюса на бъбрека насочва към <strong>рефлуксен механизъм</strong>.</p><p>При <strong>хематогенен / апостематозен остър пиелонефрит</strong> по повърхността на бледата кора проминират множество жълтеникави абсцеси с големина на грахово зърно, обградени с нежен хеморагичен пръстен. На срез се откриват абсцеси в кортико-медуларната зона, от които към върха на папилата по хода на събирателните каналчета радиерно се спускат гнойни пътечки.</p><h3>Микроскопска картина</h3><p>Микроскопски острият пиелонефрит е <strong>огнищен процес</strong> с <strong>огнищно интерстициално супуративно възпаление</strong>. В началото се установяват огнищни инфилтрати от <strong>неутрофилни левкоцити</strong> в интерстициума.</p><p>Неутрофилите се откриват и в тубулите — интраепително и в лумена, което отговаря на <strong>тубулит</strong>. Може да има и <strong>некроза на тубулите</strong>. След развитие на коликвационна некроза на извитите каналчета инфилтратите прерастват в абсцеси.</p><p>Левкоцитите се дренират в околните тубули и така се формират <strong>левкоцитни цилиндри</strong>, които се откриват в урината. В хистологичните препарати могат да се видят неутрофилна инфилтрация в интерстициума, неутрофили в лумена на каналчетата и бактериални колонии.</p><p><strong>Гломерулите</strong> дълго време остават незасегнати, дори когато са в непосредствена близост до абсцесите. При микотичен сепсис с <strong>Candida albicans</strong> процесът може да започне от тях.</p><h3>Клинична картина</h3><p>Острият пиелонефрит се характеризира с триада:</p><ol><li><strong>Повишена температура</strong>.</li><li><strong>Болки в поясната област</strong>.</li><li><strong>Дизурия</strong>.</li></ol><h3>Усложнения</h3><ol><li><strong>Грам-негативен сепсис / уросепсис</strong> — асцендентният остър пиелонефрит може да се усложни с уросепсис и ендотоксичен шок с висока смъртност. В кръвта и урината обикновено се изолира E. coli.<br></li><li><strong>Папиларна некроза</strong> — асоциира се с диабет, аналгетична нефропатия и уринарна обструкция. Обикновено е двустранна и протича с <strong>коагулационна некроза</strong> по типа на анемичен инфаркт. Пирамидите са сиво-белезникави. Във външната медула се оформя демаркационен левкоцитен инфилтрат, който не навлиза в зоната на некроза. Папилите се откъсват — секвестират, и могат да запушат уретерите.</li><li><strong>Пионефроза</strong> — Ако острият пиелонефрит се развие на фона на обструкция на пикочните пътища с хидронефроза, разширеното легенче се изпълва с гной и бъбрекът се превръща в <strong>„торбичка с гной“</strong>.</li><li><strong>Карбункул на бъбрека</strong> — възможно е сливане на по-малки абсцеси в тумороподобен карбункул. Когато той пробие капсулата на органа, се развива параренален абсцес.<br></li><li><strong>Емфизематозен пиелонефрит</strong> — характеризира се с анаеробна бактериална ферментация на богатата на глюкоза урина. В паренхима се образуват множество абсцеси, пълни с газ. Ако бъбрекът не бъде отстранен, болният загива от ендотоксичен шок.<br></li><li><strong>Перинефритен абсцес</strong>.</li></ol><h3>Изход и прогноза</h3><p>При подходяща антибиотична терапия неусложненият остър пиелонефрит има благоприятен изход, с остатъчна <strong>огнищна тубулна атрофия</strong> и <strong>интерстициална фиброза</strong>.</p><p>Ако настъпи некроза, изходът е с формиране на <strong>цикатрикс</strong>, атрофия на каналчетата, струмизация на бъбрека и деформация на легенчето и чашките.</p><p>Бактериурията може да персистира с години. Повторни атаки от други микроорганизми или нови серотипове на същите бактерии водят до <strong>рецидиви</strong> и до <strong>хроничен пиелонефрит</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Хроничен пиелонефрит</h1><p><strong>Хроничният пиелонефрит</strong> е хронично тубуло-интерстициално възпаление с <strong>цикатризиране </strong>на паренхима и <strong>засягане на чашките и легенчето</strong>.</p><h2>Клинична картина</h2><p>Поради големите компенсаторни възможности на бъбрека хроничният пиелонефрит дълго време протича <strong>латентно</strong>. Морфологичните изменения прогресират, докато заболяването се прояви с:</p><ul><li><strong>полиурия</strong>;</li><li><strong>пиурия</strong>;</li><li><strong>бъбречна хипертония</strong>;</li><li><strong>анемия</strong>;</li><li>в напреднали случаи — <strong>хронична бъбречна недостатъчност</strong>.</li></ul><h2>Морфогенеза</h2><p><strong>Обструктивният хроничен пиелонефрит</strong> възниква от повторни бактериални атаки на фона на стеноза или запушване на пикочните пътища. Може да бъде едностранен — при литиаза или уретерни аномалии, или двустранен — при вродени клапи или стриктури на уретрата. Цялото легенче е разширено, а паренхимът е равномерно изтънен.</p><p><strong>Рефлуксният хроничен пиелонефрит</strong> е по-чест. При него по повърхността на двата полюса на бъбрека се намират широки цикатрикси.</p><h2>Макроскопска картина</h2><p>Единият или двата бъбрека са силно умалени, дори под <strong>50 g</strong>, и асиметрично деформирани от широки, плитки, сивкави хлътвания, разпръснати по бъбречната кора.</p><p>При добавени артериолосклеротични изменения при артериална хипертония релефът става дребнозърнест. Кората е изтънена, особено над разширените чашки. Лигавицата на легенчетата е загрубена и дребнозърнеста.</p><h2>Микроскопска картина</h2><p>В интерстициума се установяват <strong>фиброза</strong> и <strong>кортико-медуларни лимфоидни инфилтрати</strong>, с участие на плазматични клетки и еозинофилни левкоцити.</p><p>Огнища на <strong>тубулна атрофия</strong> се редуват с дилатирани извити каналчета, в чиито просвети се намират белтъчни цилиндри. Тези участъци наподобяват щитовидната жлеза и се означават като <strong>„струмизация“ на бъбрека</strong>.</p><p>Началните изменения в гломерулите са оскъдни — колапс на капилярите и ексцентрична хиалиноза, дължащи се на исхемия. В напреднал стадий бъбречните телца се засягат от <strong>перикапсуларна гломерулосклероза</strong> — фиброза на перигломерулния интерстициум и Баумановата капсула, която може да ги обхване изцяло.</p><p>Добавената хипертония води до вторична <strong>артериолосклероза</strong> и задебеляване на интимата и медията на дъговидните и интерлобуларните артерии.</p><p>Описаната <strong>пиелонефритна нефросклероза</strong> протича с хронична бъбречна недостатъчност.</p><h2>Ксантогрануломатозен пиелонефрит</h2><p><strong>Ксантогрануломатозният пиелонефрит</strong> е особена рядка форма на хроничен обструктивен калкулозен пиелонефрит. В <strong>60%</strong> от случаите се причинява от <strong>Proteus</strong>.</p><p>Той е винаги едностранен, а понякога е локализиран само в един от полюсите. Бъбрекът е уголемен, уплътнен, жълто-белезникав и сраснал с околните тъкани. Находката може да бъде сбъркана с <strong>карцином на бъбрека</strong>.</p><p>В легенчето се намира <strong>отливъчен конкремент</strong>, а тъканта около него съдържа множество малки абсцеси и некрози. Във възпалителния инфилтрат преобладават големи пенести клетки с <strong>PAS-позитивна дребнозърнеста цитоплазма</strong>, които съдържат и липиди — <strong>псевдоксантомни клетки</strong>. Откриват се и гигантски клетки.</p><p>Възпалението може да проникне в съседните тъкани и органи. Морфологичните особености се дължат на лизозомален дефект на макрофагите. Лечението е <strong>оперативно</strong>.</p><h2>Изолирана бъбречна туберкулоза</h2><p><strong>Изолираната бъбречна туберкулоза</strong> най-често е едностранна. Процесът започва в кората като <strong>хроничен грануломатозен казеифициращ интерстициален нефрит</strong>.</p><p>Той може да се разпростре и в медулата, с формиране на кухинна лезия и улцерация на пиелона, последвани от <strong>казеозно-некротична секвестрация</strong>, обструкция на уретера и <strong>уретеропионефроза</strong>.</p><p>В хода на дисталното „спускане“ на грануломатозния процес рано възникват <strong>туберкули около устието на пикочопровода</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 72. Нефросклероза – видове. Макроскопска диференциална диагноза.</h1><p>начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 73. Хронична бъбречна недостатъчност. Патогенеза, морфология на промените в органите.</h1><p><strong>Хроничната бъбречна недостатъчност</strong> е израз на функционална декомпенсация на нефросклерозите при загуба на <strong>повече от 75% от нефроните</strong>.</p><h2>Патогенеза</h2><p>Проявите на хроничната бъбречна недостатъчност произтичат от три основни нарушения на бъбречната функция:</p><ul><li>нарушения на <strong>водно-електролитния баланс</strong>;</li><li>задържане на <strong>токсични продукти</strong>;</li><li>недостатъчност на <strong>ендокринната функция на бъбрека</strong>.</li></ul><h2>Морфология</h2><p>Морфологичните промени засягат предимно:</p><ul><li><strong>сърдечносъдовата система</strong>;</li><li>извънбъбречните екскреторни системи:</li><ul><li>кожа;</li><li>дихателна система;</li><li>храносмилателна система;</li><li>серозни обвивки.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Кожа</h2><p>Кожата е <strong>бледа</strong> поради анемията, а откритите части — лице и крайници — имат <strong>землистосив оттенък</strong> поради натрупване на урохром.</p><p>Хиперсекрецията на <strong>хлориди и урея</strong> придава „<strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-15/text-editor-images/2026/05/1778876068187-image.png &quot;width=100%&quot;)\" id=\"note-1778876069831-0\">напудрен</span></strong>“ вид на лицето.</p><p>Възможни са и <strong>кожни кръвоизливи</strong>, свързани с:</p><ul><li>неустойчивост на капилярните стени;</li><li>възпрепятстване на тромбоцитната агрегация от уремични продукти.</li></ul><p><strong>Нефротичните отоци</strong> изчезват след склерозиране на по-голямата част от гломерулите. При болни с хронична бъбречна недостатъчност може да се долови <strong>миризма на урина</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Сърдечносъдова система</h2><h3>Клинична картина</h3><p>При почти всички болни с <strong>хронична бъбречна недостатъчност</strong> се установява <strong>артериална хипертония</strong>. Нерядко непосредствена причина за смъртта е <strong>мозъчен кръвоизлив</strong>.</p><p>В терминалния стадий артериалното налягане може да се понижи вследствие на <strong>сърдечна недостатъчност</strong>.</p><h3>Морфология</h3><p>При починали с хронична бъбречна недостатъчност се установяват:</p><ul><li><strong>лявокамерна хипертрофия</strong> — в <strong>90%</strong>;</li><li><strong>дяснокамерна хипертрофия</strong> — в <strong>60%</strong>;</li><li><strong>уремична кардиопатия</strong> — хистохимични нарушения в миокарда при <strong>70%</strong>;</li><li>рядко — <strong>улцеро-верукозен уремичен ендокардит</strong>;</li><li><strong>елиминационен фибринозен перикардит</strong> — в <strong>15%</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Дихателна система</h2><p>В белите дробове се наблюдават три основни типа патологични промени:</p><ol><li><strong>Специфични изменения</strong> на белодробния паренхим, по-рядко на лигавицата на горните дихателни пътища и бронхите.</li><li><strong>Белодробен оток</strong>.</li><li><strong>Банални бронхопневмонии</strong>.</li></ol><h3>Микроскопски промени</h3><p><strong>Уремичният ларингит</strong> и <strong>уремичният трахеит</strong> имат <strong>фибринозно-некротичен</strong> или <strong>фибринозно-хеморагичен</strong> характер.</p><p><strong>Уремичният пневмонит</strong> се характеризира с голям хистологичен полиморфизъм. Типични са:</p><ul><li>дребноогнищно засягане — обикновено <strong>5–20 алвеоли</strong>;</li><li>нарушения в микроциркулацията:</li><ul><li><strong>стаза</strong>;</li><li>малки кръвоизливи;</li></ul><li>интерстициална кръглоклетъчна инфилтрация;</li><li>оток;</li><li>богати на фибрин <strong>хиалинни мембрани</strong> по периферията на алвеолите, считани за <strong>патогномонични</strong>.</li></ul><p><strong>Белодробният оток</strong> при хронична бъбречна недостатъчност се дължи главно на <strong>хиперволемия</strong> и <strong>сърдечна недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Стомашно-чревен тракт</h2><p>Откриват се <strong>фибринозни или язвени хеморагични изменения</strong>, означавани като:</p><ul><li><strong>елиминационен гастроентерит</strong>;</li><li><strong>елиминационен колит</strong>.</li></ul><p>Хроничната бъбречна недостатъчност може да провокира тежки кръвоизливи от хронични язви на стомаха и дванадесетопръстника.</p><p>Възможно е запушване на панкреатичния проток от сгъстени секрети, което води до ензимна деструкция на панкреаса — <strong>хеморагичен панкреатит</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Анемия</h2><p><strong>Анемията</strong> се развива в резултат на <strong>потисната еритропоеза</strong> и <strong>ускорено разрушаване на еритроцитите</strong>.</p><p>Потиснатата еритропоеза се дължи на намалена продукция на бъбречен <strong>еритропоетин</strong> и токсично увреждане на <strong>костния мозък</strong>, който е <strong>хипорегенераторен</strong>.</p><p>Ускореното разрушаване на еритроцитите е свързано с директното действие на <strong>уремичните токсини</strong> и с промени в ендотела на артериолите и гломерулните капиляри. Това води до травматично увреждане на преминаващите еритроцити — <strong>микроангиопатична хемолитична анемия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Имунен апарат</h2><p><strong>Хроничната бъбречна недостатъчност</strong> води до <strong>потискане на имунитета</strong>, поради което възпалителните усложнения често са непосредствена причина за смъртта.</p><p>При <strong>уремия</strong> слезката е умерено увеличена, отпусната и наподобява <strong>септична слезка</strong>.</p><p>Потискането на <strong>клетъчния имунитет</strong> има и практическо значение, тъй като подобрява шансовете за успешна <strong>бъбречна трансплантация</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Бъбречна остеодистрофия</h2><p><strong>Бъбречната остеодистрофия</strong> се развива в резултат на нарушено активиране на <strong>витамин D<sub>3</sub></strong> и <strong>паратиреоидна стимулация</strong>.</p><p>При нефросклероза се нарушава ролята на витамин D в резорбцията на калций от храносмилателния тракт. Това води до намалена калциева резорбция и развитие на <strong>хипокалциемия</strong>. Тя се задълбочава и от задържането на <strong>фосфати</strong> при бъбречна недостатъчност.</p><p><strong>Хипокалциемията</strong> стимулира развитие на <strong>вторична паратиреоидна хиперплазия</strong>. Последващият <strong>вторичен хиперпаратиреоидизъм</strong> причинява:</p><ul><li><strong>остеопороза</strong>;</li><li>заместване на костната тъкан с фиброзна — <strong>osteitis fibrosa cystica generalisata</strong>.</li></ul><p>Най-уязвима е <strong>пубертетната възраст</strong>. При деца с хронични бъбречни заболявания костната деформация се означава като <strong>бъбречен рахит</strong>.</p><p>Паратиреоидната хиперплазия може да стане автономна, при което хиперсекрецията на паратхормон продължава въпреки наличие на хиперкалциемия. Това състояние се означава като <strong>третичен хиперпаратиреоидизъм</strong>.</p><p>Поради намалена деградация и екскреция <strong>паратхормонът</strong> действа и като <strong>уремичен токсин</strong>. Той участва в развитието на:</p><ul><li><strong>уремична невропатия</strong>;</li><li><strong>уремична кардиопатия</strong>;</li><li>нарушения на <strong>еритропоезата</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Централна нервна система</h2><p>Токсичните изменения в ЦНС при уремия водят до <strong>тежък мозъчен оток</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изход</h2><p>Преди въвеждането на <strong>хемодиализата</strong> и <strong>бъбречната трансплантация</strong> болните с <strong>хронична бъбречна недостатъчност</strong> са загивали бързо.</p><p>След въвеждането на тези методи преживяемостта се удължава значително — често с <strong>повече от 10 години</strong>. В резултат броят на болните с хронична бъбречна недостатъчност нараства до <strong>200–250 души на 1 милион население</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 74. Малформации на отделителната система. Вродена поликистоза на бъбреците.</h1><p>начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 75. Бъбречно-каменна болест. Морфология и усложнения.</h1><p><strong>Бъбречнокаменната болест</strong> / <strong>nephrolithiasis</strong> е хронично заболяване, при което на всяко ниво в уринарния тракт могат да се открият уплътнени минерално-органични маси — <strong>конкременти</strong>, различни по брой, размери, форма и състав.</p><h2>Клинична картина</h2><p>Конкрементите могат при придвижване да предизвикат болезнени спазми — <strong>колика</strong>, както и запушване на пикочните пътища, <strong>хематурия</strong> и възпалителни усложнения.</p><h2>Честота и разпространение</h2><p>Заболяването засяга <strong>5–10%</strong> от населението, предимно мъже. В повечето случаи е едностранно, най-често с първа проява в третото десетилетие.</p><p>Съществува фамилно и генетично предразположение. България е в географски район с масово разпространение на нефролитиазата, като за високата честота допринася и хранителният рацион. По секционни данни <strong>21%</strong> от смъртността от бъбречни заболявания се дължи на нефролитиаза.</p><h2>Етиология</h2><p>Различават се две групи фактори.</p><h3>Общи етиологични фактори</h3><ul><li>наследствени и придобити нарушения на минералния обмен — подагра, хиперпаратиреоидизъм, наследствена цистинурия, първична хипероксалурия;</li><li>нарушения в алкално-киселинното равновесие — ацидоза;</li><li>диета с преобладаване на въглехидрати и животински мазнини;</li><li>прекомерна употреба на мляко;</li><li>неблагоприятен минерален състав на питейната вода;</li><li>авитаминоза A;</li><li>хипервитаминоза D.</li></ul><p>Общите фактори водят до наднормено образуване на <strong>оксалати</strong>, <strong>пикочна киселина</strong> или <strong>цистин</strong>.</p><h3>Местни етиологични фактори</h3><ul><li>възпалителни процеси;</li><li>намаляване на количеството и промяна на <strong>pH</strong> на урината;</li><li>нарушения в трофиката и мотилитета на уринарния тракт;</li><li>причини, водещи до застой на урината.</li></ul><h2>Морфогенеза</h2><p>Морфогенезата започва с възникване на <strong>критично ядро</strong> в бъбречната медула, което по-късно нараства в чашките и легенчето.</p><p>Според механизма на <strong>„свободната частица“</strong> ядрото може да се образува извънклетъчно в просвета на бъбречно каналче. След екскреция частицата може да се задържи в тесен сегмент на пикочните пътища. Този механизъм се основава на връзката между състава на урината като свръхнаситен разтвор и състава на конкрементите. На нивото на бъбрека е по-малко вероятен, защото урината не се задържа достатъчно време, но е възможен в пикочния мехур.</p><p>Според теорията за <strong>„фиксираната частица“</strong> в горните отдели на отделителната система конкременти могат да възникнат, ако свободните кристали в урината се прикрепят към епитела на тубулите. Кристалоидът се натрупва вътреклетъчно в тубулния епител, след което излиза на повърхността му или се излива в просвета на каналчето. Чрез „биологични лепила“, включително матриксна субстанция А и полимеризиран белтък на <strong>Tamm-Horsfall</strong>, кристалоидите полепват по хода на каналчетата.</p><p>По-нататъшната кристализация протича по физико-химични закономерности и зависи от местните фактори. Наличието на „литиазни“ съставки в урината — хиперкалциурия, хипероксалурия и хиперурикозурия — не означава задължително образуване на камъни. Литогенезата се определя и от недостатъчност на инхибитори на кристалообразуването в урината: <strong>пирофосфат</strong>, <strong>дифосфонат</strong>, <strong>цитрат</strong>, глюкозаминогликани и глюкопротеинът <strong>нефрокалцин</strong>.</p><h2>Характеристика на конкрементите</h2><p>Всеки камък съдържа органичен мукопротеиден матрикс — до <strong>5%</strong> от масата му. Според преобладаващия химичен състав се различават 4 основни типа бъбречни конкременти.</p><ol><li><strong>Калциеви конкременти</strong> — общо <strong>75%</strong> от конкрементите. Най-често са от калциев оксалат — <strong>70%</strong>, или смесени с калциев фосфат. Калциево-оксалатните конкременти са твърди, малки — под <strong>5 mm</strong>, множествени. Могат да бъдат гладки и окръглени, но по-често са с грапава, тъмно оцветена повърхност поради импрегниране с пигменти от кръвоизливите, които причиняват при придвижване.</li><li><strong>Магнезиево-амониево-фосфатни конкременти</strong> — <strong>15%</strong>. Образуват се при инфекция с микроорганизми, които разграждат уреята — Proteus и някои стафилококи. Урината остава алкална, което благоприятства образуването им. Това са т.нар. <strong>„инфекциозни камъни“</strong>. Те са единични, големи, трошливи и като светлокафяви отливки могат да изпълнят цялото легенче и чашките — <strong>„еленови рога“</strong>.</li><li><strong>Уратни конкременти</strong> — <strong>6%</strong>. Те са гладки, твърди, жълтеникави и малки — от песъчинки до <strong>2 cm</strong>, често множествени. В една четвърт от случаите болните имат подагра. Уратни камъни се образуват и при бърз клетъчен разпад, например при левкози. Възникват в кисела урина.</li><li><strong>Цистинови конкременти</strong> — <strong>1–2%</strong>. За разлика от оксалатните и инфекциозните конкременти, уратните, цистиновите и ксантиновите са рентгенологично негативни.</li></ol><p>Конкрементите невинаги са образувани там, където се намират. Днес най-често се откриват в чашките и бъбречното легенче, а в миналото — в уретерите и пикочния мехур. Уретерните конкременти и голяма част от мехурните са образувани в бъбрека. Големината им варира от песъчинки до значителни размери.</p><h2>Усложнения</h2><p><strong>Нефролитиазата</strong> може да се прояви с <strong>колика</strong>, <strong>хематурия</strong>, както и с обструктивни и възпалителни усложнения. Възпалителните усложнения включват <strong>пиелит</strong>, <strong>пионефроза</strong>, <strong>остър</strong> и <strong>хроничен пиелонефрит</strong>.</p><p>Обструктивните усложнения зависят от нивото на обтурация:</p><ul><li>при обтурация на <strong>чашка</strong> от задържаната урина се развива <strong>хидрокаликоза</strong>;</li><li>при обтурация на <strong>пиелоуретералния сегмент</strong> първоначално настъпва <strong>пиелоектазия</strong>, а при добавяне на атрофия на бъбречния паренхим — <strong>хидронефроза</strong>;</li><li>при обтурация на <strong>уретера</strong> се развива <strong>уретерохидронефроза</strong>.</li></ul><p>Бъбрекът е увеличен — <strong>псевдохипертрофия</strong>, но зад нея стои <strong>атрофия от натиск</strong>, която първоначално засяга медулата, а по-късно и кората. Хистологично <strong>хидронефротичната трансформация</strong> е близка до <strong>пиелонефритна нефросклероза</strong>, тъй като хидронефрозата рядко е асептична.</p><p>В крайната фаза бъбрекът се трансформира в <strong>тънкостенен мехур</strong>, изпълнен с урина. Обикновено хидронефрозата се инфектира и преминава в <strong>пионефроза</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 76. Тумори на бъбреците. Карцином на бъбрека. Нефробластом. Тумори на бъбречното легенче.</h1><h2>Доброкачествени тумори на бъбреците</h2><p>Най-честите <strong>доброкачествени тумори на бъбреците</strong>, произлизащи от тубуларния епител, са <strong>папиларният аденом</strong> и <strong>онкоцитомът</strong>. Към тях се отнася и <strong>ангиомиолипомът</strong>, който е смесен тумор.</p><h3>Папиларен аденом</h3><p><strong>Папиларният аденом</strong> обикновено се открива случайно при аутопсия, протича <strong>безсимптомно</strong> и се среща по-често при <strong>придобита кистична бъбречна болест</strong>.\n<strong>Макроскопски:</strong> представлява единично или множествени малки, добре ограничени възелчета с размери под <strong>5 mm</strong>, разположени в бъбречната кора.\n<strong>Микроскопски:</strong> изграден е от папили, покрити с еднослоен епител.</p><h3>Онкоцитом</h3><p><strong>Онкоцитомът</strong> съставлява около <strong>5%</strong> от реналните епителни тумори.\n<strong>Макроскопски:</strong> добре ограничен, некапсулиран тумор с охрен цвят и хомогенна повърхност.\n<strong>Микроскопски:</strong> изграден е от солидни гнезда, ацини или тубули. Клетките имат обилна <strong>еозинофилна гранулирана цитоплазма</strong> поради богатството на митохондрии. Ядрата обикновено са еднообразни, овални, с диспергиран хроматин, но могат да се срещнат и зони със значителен полиморфизъм. Размерът над <strong>3 cm</strong> и броят на митозите имат прогностично значение за по-неблагоприятна еволюция.</p><h3>Ангиомиолипом</h3><p><strong>Ангиомиолипомът</strong> е доброкачествен смесен тумор с ренална или екстраренална локализация. Той е добре ограничен, но некапсулиран.\n<strong>Микроскопски:</strong> съставен е от три компонента в различно съотношение: зряла мастна тъкан, мускулна тъкан и дебелостенни съдове. Прогнозата е добра, а хирургичното отстраняване е ефективен метод на лечение, но са описани и <strong>малигнени варианти</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени тумори на бъбреците</h2><p>Сред <strong>злокачествените тумори на бъбреците</strong> преобладават карциномите. Те се разделят на две основни групи: <strong>бъбречноклетъчни карциноми</strong>, произхождащи от епитела на бъбречните каналчета, и <strong>уротелни карциноми</strong>, произхождащи от преходния епител на пиелокаликсната система.</p><h3>Класификация на бъбречноклетъчните карциноми</h3><p>По-важните хистологични видове са:</p><ul><li>светлоклетъчен бъбречноклетъчен карцином;</li><li>папиларен / хромофилен ренален карцином;</li><li>хромофобен бъбречноклетъчен карцином;</li><li>карцином от събирателните каналчета на Bellini;</li><li>ренален медуларен карцином;</li><li>Xp11 транслокационен карцином;</li><li>некласифицируем бъбречноклетъчен карцином.</li></ul><h2>Светлоклетъчен бъбречноклетъчен карцином</h2><p><strong>Светлоклетъчният бъбречноклетъчен карцином</strong> е най-честият конвенционален карцином на бъбрека. Описан е от <strong>Grawitz</strong> като <strong>хипернефром</strong> поради приликата му със светлите клетки на надбъбречната жлеза. <strong>Синоними:</strong> тумор на <strong>Grawitz</strong>, <strong>хипернефром</strong>, <strong>светлоклетъчен карцином</strong>.</p><h3>Честота и етиология</h3><p>Среща се най-често в <strong>6-то десетилетие</strong>, предимно при мъже. Макар и рядко, може да бъде двустранен. За възникването му значение имат <strong>тютюнопушенето</strong>, <strong>затлъстяването</strong>, интоксикации с продукти на петролната промишленост и <strong>фенацетинови производни</strong>.</p><h3>Клинична картина</h3><p>Симптомите обикновено се появяват, когато туморът надхвърли <strong>10 cm</strong>. Диагностичната триада включва <strong>хематурия</strong>, <strong>болки в кръста</strong> и <strong>палпируема маса в хълбока</strong>. Около <strong>1/3</strong> от болните вече имат метастази към момента на диагностициране.</p><p>В клиничната картина могат да се включат и паранеопластични синдроми:</p><ul><li><strong>полицитемия</strong> — поради продукция на еритропоетин;</li><li><strong>артериална хипертензия</strong> — при хиперренинемия;</li><li>повишена концентрация на <strong>паратхормон</strong> с <strong>хиперкалциемия</strong>;</li><li><strong>амилоидоза</strong>.</li></ul><h3>Морфология</h3><p><strong>Макроскопски:</strong> туморната маса е <strong>едролобулирана</strong> и изпъква над коровата повърхност. На срез е жълтеникава до оранжева при обилие на липиди или сивкава. Често е прошарена от <strong>кръвоизливи</strong> с различна давност. Туморът е добре васкуларизиран, но растежът му изпреварва съдовата пролиферация, поради което възникват <strong>некрози</strong> с кистичен или желатинозен вид. От околния паренхим е отделен с прослойка влакнеста съединителна тъкан — <strong>псевдокапсула</strong>, която на много места е инфилтрирана от туморни клетки.</p><p><strong>Микроскопски:</strong> най-характерният белег е <strong>светлият воднист вид</strong> на туморните клетки, дължащ се на богатото съдържание на <strong>гликоген</strong> и <strong>липиди</strong> в цитоплазмата, които се извличат при хистологичната обработка. Част от клетките имат <strong>еозинофилна гранулирана цитоплазма</strong>. Те се подреждат в папили, тубули, алвеоли или солидни повлекла. Стромата е изградена от съдове от капилярен тип, които често кървят, което обяснява честите <strong>хеморагии</strong> и <strong>некрози</strong> и пъстрия макроскопски и хистологичен вид. Туморът има инфилтративен растеж към фиброзната и адипозната капсула на бъбрека и към бъбречния хилус.</p><h3>Градиране по Fuhrman</h3><p>Ядрата показват различна степен на атипизъм, което е в основата на градирането по <strong>Fuhrman</strong>:</p><table><tbody><tr><td>Степен</td><td>Ядрени промени</td></tr><tr><td><strong>I степен</strong></td><td>Малки сферични ядра с трудно различими нуклеоли</td></tr><tr><td><strong>II степен</strong></td><td>По-големи ядра със забележими нуклеоли</td></tr><tr><td><strong>III степен</strong></td><td>Везикуларни ядра с ясно отчетливи нуклеоли</td></tr><tr><td><strong>IV степен</strong></td><td>Подчертан ядрен атипизъм</td></tr></tbody></table><h3>Метастазиране</h3><p>Бъбречният карцином се разпространява по <strong>кръвен</strong>, <strong>лимфен</strong> и <strong>лимфохематогенен път</strong>, както и чрез директно прорастване през капсулата и в бъбречното легенче.</p><p>В бъбречната вена може да се образува туморен тромб, който да пропагира по <strong>долната куха вена</strong> до <strong>дясното предсърдие</strong>. Ранните хематогенни метастази са в <strong>белите дробове</strong> и <strong>гръбначния стълб</strong>, включително ретроградно през паравертебралния венозен плексус на <strong>Batson</strong>.</p><p>По-късно метастазите могат да засегнат <strong>черния дроб</strong>, други кости, надбъбречните жлези, контралатералния бъбрек, мозъка и половите органи. Лимфогенно се засягат регионарни и отдалечени лимфни възли, включително <strong>медиастинални</strong> и <strong>супраклавикуларни</strong>.</p><h2>Уротелен карцином на бъбречното легенче</h2><p><strong>Уротелният</strong>, или <strong>преходноклетъчен карцином на бъбречното легенче</strong>, е рядък тумор. Той възниква в резултат на малигнена трансформация на <strong>преходноклетъчния епител</strong>, който тапицира бъбречното легенче.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Тумори на бъбреците в детска възраст</h1><p>При деца се развиват няколко вида <strong>нефробластни</strong> и <strong>мезенхимни бъбречни тумори</strong>, които имат важно значение в детската нефропатология. Типични за детската възраст са <strong>нефробластомът / тумор на Wilms</strong>, <strong>вроденият мезобластен нефром</strong>, <strong>светлоклетъчният сарком</strong> и <strong>рабдоидният тумор</strong>.</p><h2>Тумор на Wilms / нефробластом</h2><p><strong>Туморът на Wilms</strong> е ембрионален тумор, произхождащ от <strong>метанефросната бластема</strong>. Развива се вследствие на фамилно предавани или спорадични мутации в <strong>11-та хромозома</strong>, като канцерогенезата му се обяснява с <strong>двуударната теория на Knudson</strong>.</p><p>Среща се най-често между <strong>2- и 4-годишна възраст</strong> и е изключително рядък при възрастни. В около <strong>20%</strong> от случаите се съчетава с <strong>нефробластоматоза</strong>, характеризираща се с многобройни остатъци от метанефроса в бъбречния паренхим.</p><p><strong>Макроскопски:</strong> туморът е добре ограничен, но некапсулиран. Обикновено е голям, с лобулирана повърхност, сивобелезникав цвят и хомогенна срезна повърхност. Може да има хетерогенен вид поради кисти, кръвоизливи, фиброза и калциеви отлагания.</p><p><strong>Микроскопски:</strong> произходът от недиференцирана бластема обяснява разнообразната хистологична картина. Най-чест е класическият <strong>трикомпонентен тумор</strong>, съставен от <strong>бластемна</strong>, <strong>епителна</strong> и <strong>мезенхимна</strong> компонента. Епителната компонента образува тубули и недоразвити гломерулоидни формации, а мезенхимната е представена предимно от фибробластни и рабдомиобластни структури. Различават се и високодиференцирани варианти — <strong>фиброепителни</strong> или <strong>кистични частично диференцирани нефробластоми</strong>. <strong>Анапластичният вариант</strong> се характеризира със значителен полиморфизъм и неправилни <strong>мултиполарни митози</strong>.</p><h3>Метастазиране и прогноза</h3><p>Прогнозата зависи от варианта на тумора. Високодиференцираните форми са с благоприятна прогноза и нисък риск. Класическият вариант е с интермедиерен стандартен риск и се повлиява добре от химиотерапия, но може да метастазира. <strong>Анапластичният вариант</strong> е високорисков, резистентен към химиотерапия и протича агресивно, с лимфогенно и хематогенно метастазиране.</p><h2>Вроден мезобластен нефром</h2><p><strong>Вроденият мезобластен нефром</strong> е най-честият бъбречен тумор през първите месеци от живота. Клинично се представя като подутина в коремчето, достигаща до <strong>15 cm</strong>, с плътноеластична консистенция, без болка и хематурия.</p><p><strong>Макроскопски:</strong> туморът е разположен дълбоко в бъбречния паренхим и прелива в него. Има сивобелезникав цвят, гладка срезна повърхност и наподобява <strong>лейомиом</strong>.</p><p><strong>Микроскопски:</strong> съставен е от източени и гладкомускулни клетки, преплетени с нормални нефрони. Наличието на напречнонабраздена мускулатура е характерно за <strong>тумора на Wilms</strong>, а не за мезобластния нефром.</p><p>Тъй като бъбрекът и туморът растат синхронно, бъбречната тъкан не е компресирана. Обикновено <strong>мезобластният нефром</strong> е доброкачествен, но е възможен и <strong>саркоматозен вариант</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 77. Възпалителни заболявания на пикочните пътища и пикочния мехур. Видове, морфологична характеристика и усложнения.</h1><p><strong>Циститът</strong> представлява възпаление на пикочния мехур. Класификацията на циститите се основава на причината, продължителността и хистологичната им характеристика.</p><h2>Етиология</h2><p>Най-честите етиологични агенти са:</p><ul><li><strong>бактерии</strong>, обитаващи дебелото черво;</li><li><strong>туберкулозни микобактерии</strong> — десцендентно, след хематогенно засягане на бъбреците;</li><li><strong>гъбички</strong> — <em>Candida albicans</em>;</li><li><strong>вируси</strong>;</li><li><strong>хламидии</strong>;</li><li><strong>микоплазми</strong>;</li><li><strong>паразити</strong> — шистозомиаза.</li></ul><p>Циститите могат да бъдат и <strong>ятрогенни</strong>:</p><ul><li>след терапия с <strong>цитостатични медикаменти</strong> — <strong>хеморагичен цистит</strong>;</li><li>след облъчване по повод генитални неоплазми при жени — <strong>радиационен цистит</strong>, хеморагичен и с атипизъм на епитела;</li><li>след продължителна катетеризация — <strong>полипозен цистит</strong>, най-често по задната стена на мехура; ако полипите са на широка основа и оточни, циститът се означава като <strong>булозен</strong>.</li></ul><h2>Остри цистити</h2><p>Клинично острите цистити протичат с <strong>често уриниране</strong>, болка ниско в корема, <strong>дизурия</strong>, температура и отпадналост. При <strong>остър хеморагичен цистит</strong> кръвозагубата може да бъде дори фатална.</p><p>Макроскопски острият цистит може да се прояви в няколко морфологични форми:</p><ul><li><strong>ерозивно-язвен</strong>;</li><li><strong>псевдомембранозен</strong>;</li><li><strong>язвено-некротичен</strong>;</li><li><strong>флегмонозен</strong>;</li><li><strong>гангренозен</strong>.</li></ul><p>Острият цистит може да се усложни с <strong>асцендентен пиелонефрит</strong>, а при гангренозна форма — с <strong>перфорация</strong> и <strong>перитонит</strong>.</p><h2>Специални форми на цистити</h2><p><strong>Фоликуларният цистит</strong> е хроничен рецидивиращ цистит с формиране на <strong>субмукозни лимфни фоликули</strong>.</p><p><strong>Емфизематозният цистит</strong> е резултат от инфекция с <strong>газообразуващи бактерии</strong> и се среща главно при диабетици.</p><p><strong>Еозинофилният цистит</strong> се наблюдава при <strong>алергична диатеза</strong>, често в съчетание с прояви от белите дробове и стомашно-чревния тракт. В периферната кръв се установява <strong>еозинофилия</strong>. Макроскопски се представя като полип или възел на мехурната стена, с хиперемия, некрози и разязвявания.</p><p><strong>Хроничният язвен интерстициален цистит</strong> засяга най-често жени в средна възраст. Етиологията е неизяснена, урината е стерилна, а лечението е трудно. Мехурът е дилатиран, с фини точковидни кръвоизливи и повърхностно разязвена лигавица по дъното и задната стена. В субмукозата има оток, а в мускулния слой — инфилтрати от лимфоцити и мастоцити, както и огнищна фиброза.</p><p><strong>Малакоплакията</strong> е своеобразна възпалителна реакция, развиваща се обикновено след <strong>5-то десетилетие</strong>. По лигавицата на мехура се формират жълтобелезникави плаки с размер <strong>3–4 cm</strong>, с централно хлътване или разязвяване. Патогенетично е свързана с нарушение на клетъчното смилане и претоварване на фагозомите с бактерии, най-често <strong>E. coli</strong>.</p><p>Хистологично при малакоплакия инфилтратите са изградени от плътно разположени големи макрофаги, между които има гигантски клетки и пръснати лимфоцити. Макрофагите имат обилна гранулирана или пенеста еозинофилна цитоплазма и се наричат <strong>клетки на von Hansemann</strong>. В тях се откриват диагностичните интрацитоплазмени включвания на <strong>Michaelis–Gutmann</strong> — ламеларно-концентрични, <strong>PAS-позитивни</strong>, желязосъдържащи калкосферити.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 78. Тумори на пикочния мехур.</h1><p><strong>Уротелните тумори</strong> произлизат от <strong>преходния епител</strong> на пикочния мехур и другите отдели на уринарния тракт — бъбречното легенче, уретера и уретрата.</p><p>Класификацията им се основава на два основни признака:</p><ul><li><strong>клетъчна диференциация / анаплазия</strong>;</li><li><strong>дълбочина на инвазия</strong>.</li></ul><p>Според дълбочината на инвазия уротелните тумори се разделят на две големи групи:</p><ol><li><strong>Неинвазивни уротелни тумори</strong>, към които спадат:</li><ul><li><strong>уротелен папилом</strong>;</li><li><strong>инвертен уротелен папилом</strong>;</li><li><strong>уротелен карцином in situ — CIS</strong>;</li><li>неинвазивни папиларни уротелни карциноми с различна степен на злокачественост.</li></ul><li><strong>Инфилтриращи / инвазивни уротелни карциноми</strong>.</li></ol><p>Биологичното поведение на туморите зависи и от генетичната им характеристика. Според нея те се разделят на <strong>генетично стабилни</strong> и <strong>генетично нестабилни</strong>. Генетично стабилната категория включва неинвазивните папиларни тумори с ниска степен на малигненост, а генетично нестабилната — високостепенните неинвазивни и инвазивните карциноми.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Уротелен / преходноклетъчен папилом</h2><p><strong>Уротелният папилом</strong> е неинвазивен папиларен тумор на пикочния мехур.</p><p><strong>Макроскопски:</strong> представлява папиларен тумор с размер <strong>0,5–2 cm</strong>, с фина разклонена структура. Подобно на глухарче е прикрепен с тънко стебло към мехурната стена, най-често в областта на <strong>тригона</strong> или входа на уретрата.</p><p><strong>Микроскопски:</strong> всяка папила е изградена от нежна <strong>фиброваскуларна строма</strong>, покрита от <strong>7 или по-малко слоя преходен епител</strong>, без клетъчен атипизъм.</p><p>Поради субективността в преценката на клетъчния атипизъм и честите „рецидиви“ папиломите дълго време са разглеждани като карциноми с ниска степен на малигненост. Тези „рецидиви“ обаче по-скоро отразяват <strong>мултифокалност</strong> на процеса. Само около <strong>10%</strong> от тях имат инвазивен потенциал.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Уротелни карциноми на пикочния мехур</h1><h2>Карцином in situ</h2><p><strong>Карциномът in situ</strong> е високостепенен интраепителен / интрауротелен тумор. Представлява плоска туморна формация, локализирана само в епитела, без папиларни образувания. Характеризира се с нарушено съотношение между слоевете на епитела и изразен клетъчен и ядрен атипизъм. <strong>Уротелният карцином in situ</strong> е преканцероза, която се асоциира с инфилтриращ карцином в <strong>45–65%</strong> от случаите.</p><p><strong>Микроскопски:</strong> установява се нарушение на клетъчните редове в преходния епител — <strong>дистратификация</strong>, комбинирана с малигнена клетъчна трансформация. Ядрено-цитоплазменият индекс е повишен, ядрата са полиморфни, често ангуларни, с груб хроматин и уголемени ядърца. Клетъчните промени могат да бъдат множествени или дифузни, да обхващат цялата дебелина на епитела или само част от него. При частично засягане пръснатите атипични клетки имат <strong>пейджето-подобен</strong> вид. Карцином in situ понякога се открива и в кистите на хроничния кистичен цистит.</p><h2>Неинвазивни папиларни уротелни тумори</h2><p><strong>Неинвазивните папиларни уротелни тумори</strong> се разделят на три подгрупи, всяка със свое биологично поведение, което корелира с геномната характеристика на туморите:</p><ul><li><strong>тумори с ниска степен на малигненост</strong> — често рецидивират, но рядко прогресират в стадия; генетично спадат към стабилната категория;</li><li><strong>тумори с висока степен на малигненост</strong> — често прогресират в стадия, а смъртността достига до <strong>65%</strong>; генетично са нестабилни и имат сходство с инвазивните карциноми;</li><li><strong>тумори с нисък малигнен потенциал</strong> — имат висок риск за рецидиви и нисък риск за анаплазия; доближават се до папилома по доброкачествено протичане и преживяемост.</li></ul><h2>Инфилтриращ уротелен карцином</h2><p><strong>Инфилтриращият уротелен карцином</strong>, наричан още <strong>преходноклетъчен карцином</strong>, е злокачествен уротелен тумор, който се разпространява извън базалната мембрана на уротела.</p><h3>Честота</h3><p>Инфилтриращият карцином на пикочния мехур съставлява около <strong>3,2%</strong> от всички злокачествени тумори и заема <strong>7-мо място</strong> сред тях в света. Развива се значително по-често при мъже, със съотношение <strong>мъже : жени = 3,5 : 1</strong>. Във високоразвитите страни съставлява около <strong>90%</strong> от карциномите на пикочния мехур.</p><h3>Етиология и рискови фактори</h3><p>Още в края на XIX век е установена по-висока честота сред работници в <strong>анилиновата промишленост</strong>. Този тумор е сред първите, при които е доказано значението на външни фактори за развитието му.</p><p>Най-важните рискови фактори са:</p><ul><li><strong>тютюнопушене</strong> — рискът при пушачи е <strong>2–6 пъти по-висок</strong>;</li><li>професионално въздействие на <strong>ароматни амини</strong> — бензидин, 2-нафтиламин, 4-аминобифенили;</li><li>някои медикаменти — <strong>фенацетин</strong>, <strong>циклофосфамид</strong>;</li><li><strong>арсен</strong>;</li><li>хронични инфекции;</li><li>паразитоза със <strong>Schistosoma haematobium</strong>.</li></ul><h3>Клинична картина и диагностика</h3><p>Най-честият симптом е <strong>хематурията</strong>, обикновено безболезнена. При локализация в шийката на мехура се появяват <strong>дизурични смущения</strong>.</p><p>Диагностиката се основава на <strong>цистоскопия</strong> и хистологично изследване на резекционен материал от тумора и подлежащия мускулен слой. Широко се прилага <strong>трансуретрална резекция на пикочния мехур — ТУР</strong>.</p><p>Поради възможното едновременно развитие на уротелни карциноми в целия уринарен тракт, включително в простатните канали, е необходимо обстойно изследване чрез образна диагностика — <strong>ЯМР</strong>, <strong>КАТ</strong> и интравенозна пиелография.</p><h3>Морфология</h3><p><strong>Макроскопски:</strong> туморът може да има <strong>папиларна</strong>, <strong>полипоидна</strong>, <strong>нодуларна</strong> или <strong>язвена</strong> форма. По-рядко се наблюдава дифузен трансмурален растеж.</p><p><strong>Микроскопски:</strong> резекционният материал се оценява по два основни белега: <strong>степен на анаплазия</strong>, която определя степента на злокачественост, и <strong>степен на инвазия</strong>, която определя стадия на тумора. Хистологичната картина наподобява в различна степен нормалния уротел. Ако туморът е изграден от папили с фиброваскуларен център, покрит с уротел, наподобяващ нормалния преходен епител и с минимален атипизъм, се определя като <strong>нискостепенен / low grade</strong> или високодиференциран. При изразен клетъчен и ядрен атипизъм и отклонение от папиларната архитектура туморът е <strong>високостепенен / high grade</strong> или нискодиференциран. При него трудно се откриват папиларни структури, а туморът е представен от солидни гнезда от полиморфни клетки с хипер- или полихромни, неправилни ядра, големи нуклеоли и чести неправилни митози.</p><p>В уротелните карциноми често се наблюдават <strong>метапластични промени</strong>, които определят хистологичното разнообразие. Най-чести са уротелните карциноми със <strong>сквамозна</strong> и <strong>гландуларна диференциация</strong>. Сквамозна диференциация се открива в около <strong>20%</strong> от карциномите на пикочния мехур и е лош прогностичен и предиктивен белег. Гландуларна диференциация се открива в около <strong>6%</strong> от туморите; жлезите обикновено са тубуларни или от чревен тип, с продукция на муцини.</p><h3>Градиране</h3><p>В последните години се препоръчва разделяне на уротелните карциноми на две степени:</p><table><tbody><tr><td>Степен</td><td>Характеристика</td></tr><tr><td><strong>Low grade / нискостепенни</strong></td><td>Съответстват на I–II степен; показват „стабилни“ генетични промени, загуба на хромозома 9 и мутации на <strong>FGFR</strong></td></tr><tr><td><strong>High grade / високостепенни</strong></td><td>Съответстват на III–IV степен; характерен е „нестабилен“ геном с увреди на <strong>p53</strong>, ретинобластомния ген, <strong>EGFR</strong>, експресия на ras протеин и др.</td></tr></tbody></table><p>Старото стадиране в 4 степени е изоставено поради по-трудната съпоставка с клиничната еволюция и прогнозата от лечението.</p><h3>Стадиране</h3><p>Използва се системата <strong>TNM</strong>. Категория <strong>T</strong> се определя според степента на инвазия в стената на пикочния мехур:</p><table><tbody><tr><td>Категория</td><td>Инвазия</td></tr><tr><td><strong>Ta</strong></td><td>Туморът е локализиран само в епитела</td></tr><tr><td><strong>T1</strong></td><td>Инвазия в субепителната съединителна тъкан</td></tr><tr><td><strong>T2</strong></td><td>Инвазия в мускулния слой</td></tr><tr><td><strong>T3</strong></td><td>Инвазия в мастната капсула</td></tr><tr><td><strong>T4</strong></td><td>Инвазия в съседни тъкани, например простата</td></tr></tbody></table><p>Категория <strong>N</strong> определя броя на засегнатите лимфни възли, а категория <strong>M</strong> — наличието на хематогенни метастази.</p><h3>Усложнения и прогноза</h3><p>Чести са <strong>хеморагичните усложнения</strong>. Смърт може да настъпи от карциномни метастази в <strong>белите дробове</strong>, <strong>черния дроб</strong> и <strong>костите</strong>. Може да се развие <strong>хронична бъбречна недостатъчност</strong> от обтурационен тип поради ангажиране на орифициума на уретерите.</p><p>По асцендентен път от съпътстващия цистит може да се разпространи бактериална инфекция и да причини <strong>пиелонефрит</strong>.</p><p>Прогнозата за рецидиви и прогресия зависи от морфологични и генетични фактори. Най-голямо прогностично значение имат <strong>хистологичният вид</strong> и <strong>степента на инвазия</strong>, определяща стадия на тумора.</p><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
